࿒࿆࿔ཫ࿲ྻ࿲ྜྷཹ༜ྖ࿲࿐࿉༡࿦཯༈ྈཟ༄ཹ྇࿯࿺༂༌྄࿔ཞཀཻ࿘༉༆ྎ཮࿃༑࿽࿇ཌ࿇ོྌ༈࿨༧ྤྸྡྷྶྷཿཞཌྷ࿗ཱན࿰༽ྼྐྵ༄དྷྐྵ༬ྣྡ࿥༪ལས࿾࿱ྪ࿋ྯྖཨ࿀༢ྂ࿡ཅྯ࿸༧࿖༯࿘࿗ྐླཎ་ཬ࿀༱ྎ࿞࿃࿦ྤ࿇࿜ྫྷྠྶཿཫན࿽ི༝ཨཝ༂ྸབྷ࿜ྚ࿥࿀ཱུྗ࿂ྎ࿝རྷྟ༌༥࿔ཎྡྷ࿝࿡࿈࿡཈༜ྦྷ࿾ཙ༩ཫཛ࿀༹཯ྀ༼ཨྡགཙ࿁࿫࿒ན࿓༫༥ྸྣཷ༐࿉ལཬ࿍༰཈྇༅ཱི༑࿁࿙ཚ཮༰༼࿤ཻ࿕གྗཀལ༙ྯྟོ༁࿌༟࿹ཏྜྷྥྈༀ࿖༑ནའར྾ྂ࿿༧ཌྷྵཡྱ༉ྀྞཟ࿂࿉ྦླྀྷོྰི༤ྜྷ࿇ྦྷྈ༸࿒༰༸࿦࿾ྫ༦པ༆ངྸ࿳ྲ࿌༿࿶ུདྷ࿯ཻ྿࿆༟࿡ྍ྅༤ྚ࿇࿐ྒྷྷ࿒ྞྊ࿦ཱུྫགྷྂ༆࿷྇ྜྷྲཱ࿂༢ྐདྷུ࿟ཹ࿆ྷོ཮ི༤ྜྷ༓ྫྒྷ༟྿ྞྖ࿦࿾ིྦྂྩ࿷࿆࿯࿖ཱ༈࿑ྐྻཻུ࿒࿆ྷཫལི༤ྜྷའ࿹ྒྷ༸༛༅ྖ༮࿾ྫགྷྂ༆ྡླྀ࿯གཱག༢ྐདྷཀྍ࿒༳ྷ༛ྰ࿰࿿࿑ྃ࿹༐༸༝༰ྖ࿦྄ཱུགྷ༾༆ཿྸུྲ༮༊༢࿸དྷྐཻ࿒࿆࿔༝ྰ࿞༤ྤ࿇࿌ྎ࿈གྷ༰༬࿦ཱིྫགྷྂཊ༄ྸཐྲ༉࿂࿤ྐ༎དཻ࿄࿆༓ོྰི࿲ཐ࿇༉ྒྷ༎྿ལ༪༺༂ྫཹྂདྷ࿷ྸ࿯ྨྞ࿂ུྐ༚ུལ࿒ཤ༻ོེིྼྜྷ࿇࿹࿵༬྿ཡྖ࿐࿾࿝ཟ྘༎࿷༌࿯ཁཱ࿂༢ྚ༒ུྴ࿒མྷ࿒ྰྫྼྜྷ༾࿹༱༸༷ྫ༡༰࿾࿞གྷ༘༆༠࿆༧ངཱང༢དདྷ࿯ཻྦ་ྷ࿨ྰ࿬༤ྜྷ࿇ྦྷ༴༸࿨༰༪࿦࿾ྫ༦༭༆࿷ྸཀྲཱ࿂࿶ཀདྷཻུྮ࿆ྷོྍྦྷ༤ྜྷ࿇࿦ྒྷ༸྿ྞ༸࿦࿾ྫ཈ྂ༆࿷྇ྜྷྲཱ࿂ྱྐདྷུ࿟༦࿆༭ོཌྷི࿻ྜྷ༓ཆྒྷཉ྿༰ྖ࿦࿾ིཛྂ༆࿷࿆࿯ྲཱ༿࿤ཝདྷུན࿒ཾྷཫྍ࿃࿑ྤ࿇࿑࿈༣༱ཿཫན࿽ྣཟ༓༆བྷ༺࿬ཚཽ࿹ྡགཿ࿗࿫࿒࿼࿿ྟ༌࿹༏ྲྊ࿡࿶࿈྿࿀ༀཁ࿽ིཏྑ༞༂ྸྵ࿥࿟༽཮࿝ྗ࿂࿱༝རྷ༭༥ྦྷྔ࿾ྏ࿝࿡༿༊ྞྖྤདཿ࿏ཀྵ༌࿀ཾ࿯༃ྚ࿬ྦྷ༉ྎ༜࿕ྂ࿟࿃འྫ࿂༝ྲ࿊ོ࿔ྻ྿ུ࿒࿅༮ྜྷཬ཈ྷཿའ࿩ྨཱཌ࿅࿀࿒࿳ྎྎ࿖ྷ༚༂༢༎ཽ཈࿾࿘༱࿪࿥༑༖࿓ྜྷ࿮ྂ࿁ྱྵ༲ཇམུྡ࿑ཙ༢࿜࿒࿞࿧ཅ࿯ཐཥཌྷ࿨ཛྷ࿍ྡྷ࿴ྞ༡࿄ཝཆགྷ࿈࿁࿫ཱ༺࿸࿚ུཬཤ༟ུྚྫྷ࿷࿃༪ཐ࿬༝ྷ༙࿦ྒྷཛྫྷ࿯༐ཱུ༖࿌࿏ྑྟྡྸ࿐ྯ࿰࿢࿶࿑ང࿊࿫࿒࿜ཪྉྨྤཞ཯ྊ࿡ྀྻ྿ྚༀ༢༙ངྷ྿ྷྏ࿼ཐྲམ྄ཻ࿖࿒ེ࿉࿱མྜྷ༨࿬ི࿘࿜༞དྲྀྎཋ࿥༡ི࿾ྫགྷྂ༆࿷ྸ༧༂ཱ༿༢༢དྷཻུྦཙྷ࿒ྰི༤ྜྷ࿇ྦྷླ༸྿༰ྖ࿦࿾ྫ༦༞༆࿷ྸ࿳ྲཱ࿂࿶ྱདྷཻུ࿒࿆ྷོྍ༖༤ཝ࿇࿐ྒྷྊ྿ྞྶ࿦མྫགྷྂ༒࿷྇࿽ྲཱ࿂ཨྐདྷུ࿟࿩࿆࿘ཱོྀི༤ྜྷ༓ྜྒྷ࿈྿༙ྖ࿦࿾ི༯ྂྩ࿷མ࿯ྲཱ༈དྐ༎ུལ࿒࿆ྷཫཡི࿻ྜྷ࿇࿹ྒྷ༸༛࿬ྖ༖࿾ྫགྷྂ༆ྡ༠࿯ྲཱ༁༢ྐདྷཀཎ࿒࿆ྷ࿡ྰི༤ྚ࿊࿌ྒྷ༸ྂ༰ཹ༉ྸཹགྷ༓༆༧཮ཱྀྰ࿕ྜྡག༚࿊ྔ࿛࿆ྦབླྀུ࿣ྸྊ࿝࿱༿ྍྞྖཨ༖࿌࿏྘༪ྶ༖ཐྲག࿹ན࿚ྣ࿝࿉࿱ཞྒ༯ྰག཈྄࿔༌༷࿊࿴ྣླ༺࿾༢࿋࿿ྷཿཞ࿩࿾ཱྰྞ࿞࿵ྴ༂ཅ༜ྺཊ࿞࿬࿻༫྄ེྒྷ༾བ༹࿱࿽ཚ༧ྮཧཋ࿀ལ࿬ཎ࿳ཱ࿐༙ྉངལ࿒ྌྷོྰི༤ྜྷ࿇࿉ྀཷ࿄༰༭࿰࿺༌ྡྷྭ࿿࿎྇࿗ྖ࿅༈༢࿰ཟཆག࿹༶࿔ོ༈࿶ྋ࿉࿗༜࿵༸༚༢ྈ࿞ྸཹཽ༨༆༮࿀ཱ཮ྱྴ࿦཮༐ཱཽུ༫༺࿴༎࿾࿑ཀྵྲྊྦྷ࿴࿂༬ྯྖ࿕࿅࿎༏༛࿴࿳༠྆ཉ࿐࿂ེ༔࿻࿜༂༎ྰ࿻࿒༵ྐ༤ྜྷ࿇࿹ྒྷ༸྿ྞ༡ྮ࿇ིགྷགྷྟཎ࿞࿊ྂ༮࿂༖࿦࿒࿞ྎ༵ཤྷྻ࿂࿯࿔࿘ཹྦྷྒྷ࿨༸࿥༑༖ྫྷ༃࿮ྂ࿵ཻ༅༉ཻ༂ྀིྚ༚྆ཪྦ࿆༦ྂ༂࿌ཚྮ༓࿹࿈ༀ༾ཿ༄ཌྷཱུྫ༎࿱ཥ࿺྇༧ྖ྆ཁ༢ཱུྣ༙ྪ༎ྐྵ༆ྎ࿋࿌༴ྜྷྎ࿯ྫྷ࿲༭༇༑ནའ༹࿮ྂཔ༽࿬࿞࿚ྸུྡཅ࿺ཀཻ཰ཝ༆ྎ཮ྺ࿓࿽࿇ཱྀ྆ྺ༓ྸྔ࿎࿝࿖ྃསༀྡམ྆ར࿐࿂ཽ཮༐ྫ࿽ྌ༹࿁࿐ཚ࿞༤མ྽࿽ྩྠྌཀ༤༖࿓ྏ࿮ྂྼ࿼༺ལ࿺༈ཾྫྚ༚࿊ཌྦ࿆྿࿇ཱུ࿹༔࿀༓࿹ྲྀ࿧༚ྸ༄ྪཱུྫ࿘࿈࿔ཆ࿾྆༺࿐࿂࿰ཻ࿱ཎཁ༞༉༆྿࿲༓༴ྜྷྏཁཬ༯ཋ༳ྒྷམཱུ༲ཡ࿾༬࿷༅ཿྤར༖༽མྒྷྌམ࿛࿆࿇ྶ࿤࿯ྗ༊ཋ࿰࿱༁ལྯྖཱི཭ངཪགྷཫ࿶࿸༧༌࿄ྕ࿗ྐཛ࿉༉ྏ༰ྒྷ༆མ྾༂ྤ࿇༜࿙ྒྷ༗༁ྕ༁ྍ཈࿎༓༆༮࿐༹ྴྀཨྡག༚ཱ྆྽࿆ྙ࿩༜༈ྗ༊ྕ༜༣࿏།࿳࿡࿝࿚ྲ༚༴ྟ࿶࿾྆༨࿐࿂࿕྇྽࿝༺࿓༶༆ཫྍ࿩࿿ྤ࿇༃༷࿒ྔ༠࿧࿑࿽ཹཟ༓༆ུ༃༮༜ྐཚ࿰ག࿷࿗࿫࿒࿺འྊྨ༿ཀྵྵྊ࿡࿴࿈྿ྑ࿍࿎࿽༲གྷབ༆࿷ྸ࿯ྲཱ࿂࿤ྐྤ࿗ཻ࿒࿆ྷོྰ࿢࿀ལ྘࿹༪࿨༎༂ྒ࿟࿽࿌༦ཀྵ࿖࿏྇࿯ལ࿅࿥༙ཅ࿔ཀཻ཰ྵཞ࿪ྕ࿇࿲ྜྷ཈ྴ࿣ྥོཹྠ࿀࿾ཚ༴ཕྒྷ࿹ྐྵྀཆྑ༅࿺༌࿋࿬ཎ࿱མྜྷ༼༮ི࿩ཱྀྣ࿂༪྘ྻཝྒྷྀ༰ྪཀྵ࿲࿁ཷམ࿯༼ཱ࿂༢ྐདྷཻོུ࿆༗ོྰི༤ྜྷ࿇ྶ࿱࿂༮ྐྵྖྪབྷ࿀ཅ༴༣༹࿺ྫཚ࿽ུ࿤ྐ༑ཻུ࿒࿆ྷོྰ࿢ཚྉ྘࿹ྫྷ།༓࿎࿨༇࿝࿌ཏྑ࿴༿ྸ༼྅ཻ࿌༿༰࿒ཽཾཊ༥༆ཫ཮ྺལ࿑࿇࿜༚཈཰࿮༛༺࿾࿗༏ྊ࿻༚༖༧ྲྜྷཱ཮ག༚࿊ྜ࿛࿆༨ྌ࿼ྨྲྀ࿉ྭ࿝࿴༸࿡༰ྖ࿦࿾ྫགྷྂ༪ྶྔཐྲལྰཆལ༤ཌྷ༶࿱ཤ࿔࿉༽ྫ༤ཽ࿒࿺ྔ༿ྮྞྖ༈ེ࿑྽࿶ཪྡྸཱྀ࿑མ༅྘࿽༎ུ༄༡༃༆྿࿋ཷ༴ྜྷ༐࿳྘࿨ྔཿྠ༧࿆ྫྕྂ༆࿷ྸ࿯ྲཱྪ།༓༟ུ༂ྗ࿑ྼ༐࿂ཛྷ࿠࿑࿊ོ࿲ྻ྿༿ྃཌ༮ྤཪྶྷྶ༣ཐྲ࿽ྑཱ࿬ྦ࿬࿉࿱࿓ཀྵཫྰད༓ྸྊྦྷ࿵࿂࿙ྯྖྤ༰ྸ࿊࿒཰࿶࿸࿇ྌ࿐࿂ེ༲࿡࿢ཌཊ༥༆࿐࿨࿞༤ཷྻྲྔཧྩ࿥༑ྮྀིགྷ࿨༴ྍ࿸࿗༆࿗ཱུ༢ལ༻ཙཎྃྐྵྺ༆༰࿾༩ཇྶཿྔྮ།ཱུཹཁ࿝༧࿊༤࿍ྐྵྞ࿌ྴ࿜ྜ༮ྰྼྞཾ࿡འ༺༯ྰ࿾࿔࿳࿍ྡྷ࿱ཀྵ༲࿖྆ྲྫྗྭ༛༲࿜༵ཡ༂ྵ཮གྗ࿯ཻ࿒࿆ྷཱོ࿣࿈ཝྌ࿹༷༸྿༰ྖ࿦࿾ྫཏཨྋ༂ྸྵྯ཭༰཮༳ཧ࿂࿟࿡ཞ࿻༯ྰར༞཯࿍࿤༷༷࿴ཹྨ࿹࿾ད࿧ྉཥ཮࿌ྀྜྷ࿛༉࿶ྐ༦࿉༖ྂ࿾ྷླྰི༤ྜྷ࿇࿹ྒྷྊཱྀ༙༨࿦༽࿖཰࿨ླ༲ྫ࿉ྨ༉༸࿓࿸དྷ༲྄༫ལ࿃࿓ཾ࿬༔༉྘࿹ཕ྾ྔྍ࿿༜ྜྷ࿌ྯ࿃༬࿷༶ེ࿜࿅࿥࿕གྗཀ࿝࿹༭ྛོླྀླྀ༡ཷྠཙ༫༕࿐༥༨࿦ྵམ༆ཉྟ༲࿺༺༆ྱཁ༢ཤ།཯༶࿪༉ྉྎ཮࿩ྡྷྡ࿇༢྆སྼ࿾࿴ྡ࿢࿗པྊ࿋ཱྀ༙བྷཛྷ་ཇཷྍེ྆࿉࿱མ༶༐࿌ི༸༲࿭ར༯༐༻༈༛࿟࿽࿌ཏ࿶཈༿ྸ࿥ྪྐཚལི༱࿷࿦ས༥༆྿࿲༬༴ྜྷཹམྙྭ༆༂༑ནཱུ࿼ཡ࿔༸࿷཭༹࿟ད༌༇༮ྠ࿉࿆࿃༵཈༆ྲ࿀ཞི࿲མ࿘༤ྌ࿳྿༧ཱ࿯࿘࿃ྛཌ༵༅ཽྑ༹༠༅ྼཇ༄ༀ༥ཝགྷ࿜ི༎༉༛ྑཕ࿨ྲྀ࿑ྒཆད࿳༏ྒྛཤྚ༅࿬རྞཱ༌࿵ཱ༁ཀྵ༰࿁ཀྵ༁ྨ༏ྨ༯࿤ྊཧབ༁༷࿟༉࿌ྯཅ࿈࿷࿑࿐ཱྀ༠ྵ྅࿹ྠ࿬མྟ࿫࿻ྣ࿯࿑྘࿼ྷྲ࿛࿪བ༈࿁ཆ࿫ྰ࿇ཋཫ཮ཌྷ࿐࿬࿝༹༙࿅༩࿯ཻ࿫࿆ྷོྰི༤ྜྷ࿊࿡ཅྻ྿༂པ༜དཱིྃ࿲ཧཿའ࿩ཱཱུ࿜༂ཻགྷཁ༺࿱༥࿘࿉཯ཆ༤༮྿ཙ༷ྕ࿇ད༤ཁ཯࿌࿏ྗ༆࿷ྸ࿯ྲ࿝ླ࿼ྐྶུ࿊࿒࿆ྷོྰི༤༶྆༲ྒྷ༸྿༰ྖ࿦࿾༲གྷྱ༆࿷ྸ࿯ྲཱ࿂࿤ྐདྷཻུ࿒࿭྅࿑྅࿢ྍཾ྘࿹༭༯༆ཾ࿁གཇ࿌༦ཀྵ༄༑྇࿯࿐࿎ནཻྔཛཀཻ༐ྐྵༀྷྕྠ࿲ྜྷཹཙ࿣ཹོཹྐ࿹࿾༧༩༣༝ཇ༲༅ྜྷ༉༸཈࿸དྷ࿥ཙ༐ྵའའུ࿽࿻ྷ༖༺ྒྷྂྼ࿤࿴ཱིྰ༳༞གྷྣ࿶࿸࿗ྖ࿱༢༢ཱུྭིྸ༒༲ྼ།࿾ཾྲྀཽགྷ࿽༎༻ྺདཹུྤ࿂༬࿈࿒࿰࿅ྡ྅࿺࿺྄ཌྷྼ࿦༳༆࿰࿇༭༢མཊྞྮཨཅཋདྷ༙ྃ࿶ཱིུཆ࿅ཊ࿷ི༮ྍག࿠࿴ྚདྷ࿼༂ྶ࿬ྜྷཫྍིཹ༊གྷཱྀཻ༉༛༰༭ྸ࿽࿌༦ྗ༄ྸ༌࿯࿹࿕ྰ࿦༉࿡࿐࿳༒ཝ༆ྎ࿲ྻ༴ྜྷ༣མྖོཋ࿶ཏ༜ཱུ࿼ཽ༱ཊ࿷ྀ༰ེ࿅ཕྀྚདྷ࿬࿦བ࿰༶྅ྍིཪ࿾ཥ࿝࿱༿ྫྷྐྵྖཱི࿉དཛ࿨࿁࿚ཚ࿜྅࿚ུ࿤ྐྏཻུ࿒࿆ྷོྰྫ࿲ྷཥྦྷྒྷ࿱࿓ྱྉྮ࿝ིགྷ࿧༣ྱྀ࿊࿇༮࿂༂ྐྵ༘ྵ࿱࿥ཤྷ྆ཐ࿬༝༶࿇࿞ྒྷ༸྿༰ྖ࿦࿾ི༦ཾ྆ྡྸ࿼࿥་ུ྘࿕༎ུམ༸࿞༆࿐༮ྫ༤༲࿲࿽࿡ྪ࿍ྞྖྤ࿺ཿ࿏ཀྵ༌ཀཾ࿯ཽ༢࿹༔༅སྞ࿦࿠ི྿སད࿂༝ྲྌ࿹ྒྷ༸྿༰ྖ࿦࿾ྫཏྑྖ༂ྸ࿦༃ཌ࿼ཡ࿖࿧ྜ࿝࿹ྦྟོ࿽ཱུ༪࿀༣ཙྌྭྃ༇༑ནམ༰ཏཨཿ༿ྸི࿜༢࿅༿࿀࿵ེ༺࿠༥༆྿࿋༜༴ྜྷཹཾྮ࿿ྻ༇༑ནཱུ༲ཆ྾༬࿷ཝ༇༇༳༵ན༹ྗ྆࿩࿛࿆ླཋ࿶࿸དྷ༉ྏ࿝࿱༿ཱྀ࿟ྖྪཚ༃༑ཧ࿡༜࿉ཷ཮࿑ྵྯ࿹ཫཿཁ༩ྫ༆྿࿲ཊ༴ྜྷ࿴༜༫ྈ༆༂༑ནྸ࿮ྈ༓༆࿺࿦ཽ཮࿝ཨྡག༚ྌ࿳࿛࿆ཟ༐ཿ࿶࿁ཻྺ༢࿱࿂ཪྞྖ༶ན࿗࿨ཀྵྲག༧࿯ཱིཽ࿶༈༹༱ཌྷ࿶༒ེཋྼདད༫༺ཉ༥༕ྎ༭ཿྠྸྸཹ࿰࿇༆ཎྚླྀ༺ྱཱྀཇཷ࿍ེ࿉࿱ཤ࿘࿉༱࿞༤༙ྶྜྷྫྷ࿛༸࿥༑ྮཉཆགྷ࿮༴ཚཝ࿦྅࿚ུ༾ལ༎ུ༮༱ལ༆྿ྕ࿝ྈྜྷ༐ཿ༬༕ྲྀ༳࿿ཤ༺࿕࿏ྶ༪ྏ࿍ཐྲ༥ྰྦྷ࿫ྒྷ༅ང࿱ཤ༻ོྰིྏྜྷ࿇࿹࿵༡྿༰ྖ࿦࿾༶ཟ྘༎࿷࿆࿯࿳ཱ࿂༢ྚ༒ཻུ࿒࿾ྷ࿒ྰྫསྜྷ྆࿹࿱༸྿༰༡༼࿾༰གྷྲྀ༆࿆࿆༧ཝཱ༁༢ྐདྷཻུྦ࿷ྷ྿ྰི༤ྜྷ࿇ྦྷྕ༸࿒༰༒࿦མྫ༦ྃ༆ངྸྍྲཱ࿂࿶࿗དྷ࿗ཻ྿࿆࿮࿡ྍ༮༤༶࿇ནྒྷ༸྿ྞ༞࿦ྸྫ༗ྂ༆࿷྇༥ྲ༖࿂ཐྐྶུ࿟࿱࿆ྷོྪྞ࿿ྜྷ༓࿰ྒྷ࿠྿ྫྖ࿦࿾ི༕ྂྖ࿷ྸ࿯༜༖༈ཱིྐྶུལ࿒ཁ༫ཫ཯ི࿿ྜྷ྆࿹࿴༸༛བྷྖ࿦࿾༳ཟྲྀ༆ྡླྀ࿯༄ཱ༌༢ྐདྷཀཷ࿒ྸྷ࿡ྰ༺࿿࿑ྃ࿹࿴༸ླ༰ྖ࿦ཱཱུགྷཀྵ༆་ྸ࿯ྲ༮༳༢ྚདྷ༧ཻ࿒࿆࿔ཥྰྞ༤࿑࿇࿐ྒྷ࿈ྒྷ༰ྖ࿦࿎༰ཟྂཊཨྸ࿯ྲ࿰༿ཱྀ཭༎༁ཻ࿒࿆ྋ࿡ྚྞ࿲མ࿇࿹ྒྷ།࿒ར༪༺ྡྫཟྂ࿈࿷ྸ࿯ྨཇ࿂ཌྐྏུ༂྿ཤ།ོཌྷི༒ྜྷ࿇࿹࿵࿓྿ྫྖཱ࿾༰གྷ྘༟࿷࿆࿯࿟ཱ࿂༢ྚྌྀུ࿒ྸྷ༵྆ྫྒྷྜྷྌ࿹࿛༸྿༰༡࿢࿾༰གྷྗ༆ཙྸ༧༂ཱ༁༢࿑དྷཻུྦྤྷ࿒ྰྜ༤࿳྆ྦྷླ༸ོ༰ྖ࿦࿾ྫ༦ྟ༆ྡྸ࿳ྲཱ࿂࿶࿤དྷ࿯ཻ࿡࿆༫ོྍ࿬༤ཝ࿇ྰྎ࿏࿒ྞ཰࿦མྫྌྲྀ࿔ང྇࿕ྲ࿦࿂ཌྐདྷུ࿟࿩࿆࿘ོ༧ི༤ྜྷ༓࿅ྒྷྊ྿༲ྖ༢མི྿ྂཊ࿷࿦࿯ྲཱ༈ྜྷྐྻུ༇࿒࿆ྷཫཻི࿻ྜྷ࿊࿹࿴༸༛ཌྷྖཱ࿾༲གྷཀྵ༆ྡཛྷ࿯༄ཱཱཌདདྷཀ༹࿒࿾ྷྣྰི༤࿑ཅ࿹࿴༸࿡༰༴༉ཱཱུགྷཀྵ༆ྜྸ࿯ྲ༮༳༢ྚདྷ༔ཻ࿒࿆࿔ཏྰ༰༤ན࿇࿹ྒྷ࿈ཧ༰༆࿦ཱུྫ༝ྂཊ࿶ྸ࿳ྲྵ༿࿤ྐ༎࿷ཻ྿࿆ྌ࿡༃ྞ࿲ྲ࿇༙ྒྷ࿈࿒ར༪༺༥ྫཟྂ༓ངྫ࿳ྨ࿚࿂ཌྐ༘࿗࿎྿ཤ༻ོཌྷིཋྜྷ࿇࿹࿵༡྿࿼ྖཱ࿾དཟ྘༎࿷࿾࿯ཚཱ࿂༢ྚ༒ུལ࿒࿾ྷ࿡ྰྫསྜྷྌ࿹ྩ༸྿༰༡࿞࿾༲གྷྗ༆༜࿆༧ྡཱྪ༢࿾དྷཻུྦ༁ྷ࿒ྰྜ༤༶࿇ྦྷྈ༸ོ༰༒࿦࿾ྫ༦ྛ༆ཿྸ࿗ྲཽ༿࿶རདྷཀཻ࿒࿆ྷོྍཷ༤ད࿇࿐ྒྷ༸྿ྞ༚࿦ྸྫཏྂ༒࿷྇ཙྲ࿦࿂ར཭༛࿗࿟࿱࿆༑ོ༇ྞཥཝ༓࿰ྒྷྊ྿ྫྖ࿦࿾ི༣ྂཊ࿷ཎ࿯ྲཱ༈ཙྐ༎ུ࿟࿒ྰ༫ཫ࿅ིྕྜྷ྽࿹ྒྷ༸༛༖ྖ༮࿾ྡགྷྂ༆ྡྪ࿯ྨཱྪ༢དདྷཀ༅࿒མྷ྿ྰྫ༤࿑༚࿹࿴༸࿣ྫ༒࿦ཱུཎགྷཀྵ༆࿆ྸ࿯ྲ༮ག༢࿑དྷ࿳ཻ࿊ྸ࿔ཏྰྫ༤ན࿇࿹ྒྷ࿈གྷ༰࿪࿦༖ྫགྷྂཊྨྸཀྲམ࿂༢ྐ༎࿽ཻ࿡࿆࿔ོཌྷི࿲ྲ࿇࿐ྒྷ༏࿒༲ྖ༺༥ྫ༝ྂ࿠ངཆ࿳ྨན࿂࿤ྐ༎࿗࿎྿ཤ༆ོཌྷི༣ཝཋ༙࿵྆྿࿼ྖལམགཟ྘༟࿷࿾࿯༈ཱ࿂༢ྚ༨ུ࿝࿒མྷ༻༵ྫྒྷྜྷ༓࿹ྻ༸྿༰༡࿢࿾࿼གྷྗ༆ངྸ༧༂ཱྪ༢࿹དྷཻུྦ༶ྷ྿ྰ࿢༤༲྆ྦྷ༤༸༛༰པ࿦࿾ྫ༦࿘༆ཿྸུྲ࿦࿂࿶࿯དྷཀཻ࿡࿆ྷོྍ༙༤࿑࿇ྦྷྒྷ༪࿒ྞ࿘࿦༳ྫགྷྂ༆࿷྇ྜྷྲ༺࿂ཐྐདྷུ࿟༦࿆࿔ོ཮ི࿿ྜྷ༓࿝ྒྷྊ྿ཱྀ༪ཱམི࿏ྂ༪࿷࿟࿳࿑༖༈ཁྐ༎ྀུ࿒࿆ྷཫ࿚ིྕྜྷ࿿࿹ྒྷ༸༛༵ྖ༅࿾ྞགྷ࿨༒ྡ࿕࿯རཱ࿖༢ྐདྷཀཚ࿒༳ྷཧྰི༤࿑཰࿹ྉ༸ོ༰༆࿦ཱུ཮གྷ྘༆ྡྸ࿎ྲ༮࿯༢࿑དྷ࿚ྀྦ࿆࿔࿃ྰྫ༤࿳࿇࿹ྒྷ࿈࿃༰༡࿦ཱུྫྛྲྀཊྨྸ࿎ྲ࿖࿂༢ྐ༎ཱིཻཫ࿆ྉོྰི࿲༢࿇྅ྒྷྺ྿༰ྖ༺࿂ྫ༦ྂཊ࿷མ࿯ྨན࿂ཐྐྔ࿗࿟࿒ཤྫྷོ཮ི࿭ཝྉ༙࿵ྗ྿༲ྖ༺མགཟ྘༭࿷࿾࿯࿎༖༺ཌྚྗུ࿝࿒ྐ༫ྋ༵ྫསྜྷ༓࿹ྡྷ༸྿༰༡࿰࿾ིགྷ྘༆࿫࿆༧ྡཱ༂༢ཇདྷཻུྦ༁ྷཫྰྜ༤ཝ࿇ྦྷྈ༸༛༰༱࿦࿾ྫ༦ྛ༆ྡྸ༧ྲ࿤༿࿶ཾདྷྱཻྭ࿆ྷོྍ༖༤࿑࿇࿐ྒྷཕ྿ྞྋ࿦༳ྫཏྂ༆࿷྇ཿྲ྄࿂ྑྐཞ࿗࿟༱࿆ྔོྰི༤ྜྷ༓༰ྒྷྋ྿ྞྖ࿦࿾ིྦྂྩ࿷࿾࿯༄ཱ༈࿽ྐྻུ༠࿒࿆ྷཫྫིྕྜྷ༩࿹ྊ࿠༛༖ྖ༮࿾ྐྵགྷྂ༆ྡ࿕࿯གཱ࿷༢ྐདྷཀྰ࿒྇ྷ྿ྰྜ༤࿑༚࿹࿵༸ྟྫ࿪࿦ཱེུགྷཬ༆ཿྸན༄༮ག༢ཝདྷཀཻ༭ྸ࿔཈ྰ༲༤཭࿇ྞྎ࿈བ༰࿪࿦༳ྫཥྂཊཱུྸཀྲ༌࿂༢ྐ༎཭ཻཫ࿆ྔོ࿆ྞ࿲༢࿇྅ྒྷྺ྿༰ྖ༺༂ྫ࿮ྂྙ࿷ྸ࿯ྨྞ࿂ཨྐ༚ུལ࿒ཤའོཚིྕྜྷ༻࿹࿵྆྿ྞྖ༁མྞགྷ྘༑࿷྇࿯༥༖ྦྷཌྚྗུ࿟࿒༢༫༸༵ྫ༝ྜྷ༓࿹༯࿠࿈ྫ༡ཇ࿾ྞགྷ༏༆࿷ྸ༧࿕ཱ༂༢༶དྷཎྀྦ༇ྷྦྰཛྷ༤ྜྷ࿇ྦྷྕ༸ྦ༰༆࿦མྫ༦ྃ༆ཁྸྜྲཱ࿂࿶྇དྷྱཻ༛࿆࿮࿡ྍ༮༤཭࿇࿫ྒྷ༸྿ྞ༚࿦༳ྫ༝ྂྖ࿷྇ྐྲ༺࿂ཐྐདྷུ࿟ྺ࿆ྔོ࿀ིྠཝ༓ལྒྷྋ྿༰ྖ࿦࿾ིྮྂ༬࿷ཤ࿯ྲཱ༈དྐ༞ུ࿝࿒ྸྷཫ༰ིྕྜྷ࿓༙༷࿠༛བྷྖ༅࿾࿤ཟ༞༒ྡ༃࿯རཱ༿༢ྐདྷཀ༹࿒༳ྷ༨ྰི༤࿑༟࿹༱༸ཫ༰༴༉ཱཱུགྷ༓༆ྯྸ࿯ྲ༮༳༢༥དྷྡཻ࿒࿆࿔ཥྰ࿼༤ྚ࿇࿐ྒྷ࿈བ༰ཊ࿦ཤྫ࿁ྂཊ࿶ྸ࿎ྲ࿂༿ཨྐ༎དཻཫ࿆࿇ོྰི࿲ར࿇ཎྒྷཉ྿༉༪༺༂ྫ࿁ྂ༤࿷ྸ࿯ྨྫ࿂࿗ྐ࿵ཻུ࿒ཤ།ོི༹༛ྜྷ࿇࿹࿵࿓྿࿢ྖ༺࿾༲གྷ྘༭࿷ཤ࿯࿤༖࿕༢ྚྗུ࿅࿒ཙ༫ྋ༵ྫ༝ྜྷ༩࿹࿵࿠࿈ྫ༡࿺࿾ྞགྷ༬༒༙࿆༧ཛྷཱ༂༢࿆ྏ࿰ྀྦ་ྷྦྰ࿉༤ྜྷ࿇ྦྷ྽༸ླ༰ཊ࿦ཚ༰༦ྔ༆ླྀྸ࿦ྲཱ࿂࿶࿤དྷ༧ཻོ࿆༫ོྍ࿐༤཭࿇ྐྒྷ༸྿ྞ࿈࿦ཤྫཥྂ࿍ང྇༃ྲ༅࿂ཤྐདྷུ࿟༦࿆ྔོཌྷི࿏ྜྷ༓ྜྒྷྋ྿༲ྖ࿦࿾ི࿲ྂ࿪࿷ཱུ࿯ྪ༖༈ཁྐ༟ཻུ࿒࿆ྷཫཱྀིྭྜྷ༻࿹ྒྷ༸༛༮ྖ྄࿾࿼གྷྲྀ༆ྡླྀ࿯གཱཽ༢ྐདྷཀ྄࿒༳ྷ༛ྰ཭࿿࿑ྃ࿹࿭༸༻༰ྖ࿦ཱཱུགྷ༩༆࿂ྸ࿯ྲ༮࿾༢ྜྷདྷ࿳ཻོ࿆࿔ྎྰ༲༤༺྆྅ྒྷ࿈ྼ༰ྩ࿦༳ྫ༪ྲྀཊཤྸཐྲ༺࿂ྜ཭༎ྜྷཻ࿛࿆ྛོྴྞ࿲༌࿇྅ྒྷྋ྿ྯྖ༺ྡྫ࿮ྂ࿛࿷ྸ࿯ྨ༜࿂࿗ྐ༟ུ༁྿ཤ།ོི༹ཀྵྜྷ࿇࿹࿵ཪ྿ཡྖ࿉࿾ྫགྷ྘ྏ࿷ག࿯༌ཱ༁༢ྚུ྆࿰࿒༳ྷ༯ྰྫ༝ྜྷ༻࿹༾࿠ཫ༰༡࿺࿾ྜགྷ࿠༒༉࿆༧༶ཱ࿕༢࿂ྏཻྀྦ༥ྷྦྰ༵࿿༽྆ྦྷྈ༸ཫ༰ཉ࿦࿾ྫ༦ྛ༆ླྀྸྱྲྑ༿࿶ཾདྷཌཻ྘࿆ྷོྍ༖༤ྐ࿇࿐ྒྷ࿠྿ྞྋ࿦྇ྫྲྀྂ༆࿷྇ཿྲ༅࿂ཾྐྼ࿗࿟ཟ࿆ྛོ࿢ི༤ྜྷ༓཯ྒྷྋ྿࿼ྖཱ࿾ི༣ྂ༬࿷࿾࿯ྲཱ༈ཙྐ༟ུ࿫࿒࿷༫ཫྐྵིྭྜྷ࿇࿹ྒྷ༸༛࿹ྖ࿐࿾࿢གྷྂ༆ྡྪ࿯ཱཱུྪ༢཭དྷཀ࿉࿒༳ྷཛ༵༽࿿࿑༚࿹༱༸ྛྫྔ༉ཱུ࿬གྷ༓༆ངྸ࿯ྲ༮༊༢༥དྷ࿀ཻ࿒࿆࿔྾ྰྐྵ༤ཱི࿇࿗ྎ࿈གྷ༰༬࿦༖ྫགྷྂཊྨྸ༢ྲ࿹࿂༢ྐ༎࿽ཻ࿄࿆࿘ོཌྷི࿲ྸ࿇࿦ྒྷྻ྿ཆྖ༺࿽ྫ࿁ྂཏངག࿯ྨ࿞࿂࿗ྐཞཻུ࿒ཤ༓ོ࿬ི༴ྜྷ࿡༙࿵ཪ྿ཆྖྲ࿾ྫགྷ྘༎࿷༊࿯࿦ཱ࿂༢ྚཊུན࿒ཎྷོྰྫྉྜྷ྘࿹࿵༸࿡༰༡࿚࿾࿢གྷཊ༒༂ྸ༧༶ཱ༇༢༧ྏ࿰ྀྦྚྷ༛ྰྫ࿿༽྆ྦྷ༕༸ཫ༰༻༉࿼༰༦ྶ༆ླྀྸ་༄ཿ༿࿶࿯དྷཌཻ྾࿆ྷོྍ࿹༤ྤ࿇࿦ྒྷ࿵࿒ྞ༞࿦༊ྫ༱ྂ༆࿷྇༥ྲ࿐࿂࿤ྐྏུ࿟࿩࿆ྛོཁི༤ྜྷ༓࿅ྒྷྻ྿ྯྖ༢མི྿ྂཪ࿷ྑ࿯ྲཱ༈དྐ༟ུལ࿒࿾ྷཫ࿚ིྭྜྷ࿊࿹ྒྷ༸༛ྦྷྖ༙࿾ྯགྷྟ༒ྡ༥࿯ཤཱ࿂༢ྐདྷཀྵ࿒༊ྷ༯ྰི༤࿑཰࿹༐༸ོ༰༪࿦ཱུཎགྷ༩༆࿢ྸ࿯ྲ༮ག༢༥དྷ༢ཻ࿊ྸ࿔ཏྰཇ༤༠࿇࿹ྒྷ࿈གྷ༰ཪ࿦༄ྫགྷྂཊ༄ྸ࿤ྲ༉࿂࿤ྐ༎࿂ཻ࿛࿆༣࿡ི༹࿲༧࿇༉ྒྷྋ྿ཱུ༪༺ླྀྫ཈ྂ༬࿷ཻ࿳ྨྯ࿂࿳ྐྋེུ྿ཤཪོི༹ྭྜྷ།࿹࿵ྩ྿ཡྖ༄࿾ྫགྷ྘ཉ࿷༊࿯ཤཱལཌྚཊུན࿒༉ྷོྰྫྒྷྜྷྂ࿹བ༸྿༰༡࿢࿾ཽགྷཀྵ༆ཙྸ༧࿸ཱྡ༢༥དྷཐཻྦ༥ྷ༯ྰམ࿿ཱི࿇ྦྷ྿༸࿄༰ྟ༉ཡ༰༦དྷ༆༂ྸ༊༄ྡ༿࿶༊དྷཌཻྠྸ྽࿡ྍ࿐༤ཱི࿇࿢ྒྷ༸྿ྞ࿙࿦༊ྫྣྂྡྷང྇༃ྲ࿹࿂༊ྐདྷུ࿟༦࿆པོཌྷི࿿ྜྷ༓࿞ྒྷ༎྿༰ྖ࿦࿾ིླྂ༨࿷ྸ࿯ྲཱ༈࿽ྐཉུ࿬࿒࿆ྷཫྫི࿧ྜྷ༾࿹ྏ࿠༛࿉ྖྦྷ࿾ྫགྷྂ༆ྡ࿷࿯ྲཱ༇༢ྐདྷཀྵ࿒࿆ྷྮྰི༤࿑཰࿹བ༸࿡༰༪࿦ཱུཎགྷ༘༆༵ྸ࿯ྲ༮ཱུ༢࿽དྷ࿤ཻྗྸ࿔ཏྰྯ༤མ࿇࿹ྒྷ࿈ཧ༰ཪ࿦ྸྫ༝ྂཊ࿾ྸཾྲ༖࿂༢ྐ༎࿸ཻ༣࿆ྷོྰི࿲ྱ࿇༮ྒྷཊ྿༰ྖ༺ླྀྫྺྂཞ࿷࿀࿳ྨྫ࿂༧ྐ༐ཻུ࿒ཤཀྵོྵི࿏ྜྷ྆࿹࿵༾྿཯ྖཎ࿾ྫགྷ྘ཉ࿷ྲ࿯ཱ྇࿹ཌྚྩུ༜࿒༄ྷ࿔༵ྫ࿭ྜྷ༪࿹࿴༸྿༰༡ཆ࿾ྫགྷ྆༆࿷ྸ༧༁ཱ࿂༢࿽དྷཻུྦ࿷ྷོྰཆ༤ྜྷ࿇ྦྷ࿍༸྿༰༡࿦࿾ྫ༦༚༆࿷ྸ࿯ྲཱ࿂࿶ཀདྷཻུ༕࿆ྷོྍཷ༤ྜྷ࿇༉ྒྷ༸྿ྞ࿠࿦࿾ྫ࿮ྂ༆࿷྇ྪྲཱ࿂࿤ྐདྷུ࿟ཹ࿆ྷོ࿀ི༤ྜྷ༓ྫྒྷ༸྿ཡྖ࿦࿾ིྮྂ༆࿷ཤ࿯ྲཱ༈དྐཕུ࿝࿒࿾ྷཫ༜ིྥྜྷཀྵ࿹ྒྷ༸༛྅ྖ྅࿾྅གྷྂ༆ྡྡ࿯ྸཱཙ༢༲ྏཀྰ࿒༄ྷ࿡ྰྞ༤࿑࿙࿹ཋ༸྿༰ྖ࿦ཱུ༅གྷྂ༆࿓࿣࿯ྲ༮ྱ༢ྐདྷ࿗ཻ࿒࿆ྷ࿒ི༹༤ཿ࿇ཡྒྷཕ྿ིྖ࿦࿾ྫགྷྂ༆ཿཞྈཱཱེུྦྷྍ࿡ྴ࿑࿱༥࿘࿐༛࿅༤༜ྦཙ༒࿛ྖ༿࿁ཨཻཌ༗ཧྦ࿶࿸ུྲཱ࿂༢ྐདྷཻུ࿒མྜྷད࿬ི༚྄཈࿽༑ྺ࿴࿥༡༖ཞྵ༦ྂ࿧཮࿦༲༒༩༈༢ཎ༘ྴ࿸༙ྭ࿔ོ࿳ྍདྷྲ࿊ོྊྻ྿༿ྒྷ࿅ྚཐཬ༸ྷཿཞྉཱཱུ཯྄࿼ཥ࿫྄ྛ࿐࿘࿐ྫ࿞༤ཻ཈རྶ༪ྷཌྷ༑༖འམ࿮ྂༀ࿌ྀ࿢࿚མུྡྚ༚࿇༃࿛࿆ྎ࿘༲༔ཕ࿉ྏ࿝ྀར࿄༰࿋࿰༜ཤ༎ྒ࿒࿶འ༔ྨཱ࿹࿷༙࿱ཀ࿝࿉༕ྛོ༊ྍཪ྅༞༊࿡࿊༙༅༨࿦཮༢ྈ࿒ྦཡ࿸༁༆ྙ༈༢༖ྣ༲༄࿡ྫྷ྿ཫྰ༇༓྅༐࿉ྀྠ༛༰ྕཆཇ࿌༝ྲྀ༒࿷ྸ࿯ྲཱ࿂༢ྚ༚ྌ྅࿛࿆༯༡ྪཱུ༩࿺ྊ࿝ལ༩࿄༰ྛ༶ྐ༿࿧༸ྷ࿶࿓༇ྨ྄ཱ࿐༹ྗ࿳࿱༘རྷྂཿ༶ྏྰྈཝ༣࿈ོཹཆ࿹࿾ཤ࿘༣ཋ࿯࿞༁ྜྷ༯࿛࿗ྐ࿏࿞ཱྗྵ༱ྎ࿞ྺ༶࿑࿇༧཰ས࿴࿼ྖ༉࿾ྫགྷྂ༆࿷ྸ༧࿖༯ཱ࿗ྐྡྷ࿚༮ༀ༃ོ཰࿞࿃ྰྤ࿇་༯༘ཅཿྛ༂࿽࿼ཽཛྷྌ࿷࿉ཿ࿝དྵྀ༳ྈ࿼༉ྖ༶࿃཰ླྀཁ࿲ྚུཌྷ࿵༸༗༳࿴ྤའ༜༦ྂྕཱྀན࿜༒࿬༈༢༌࿲࿥༄࿡࿓ྪཫྰ༠࿘࿾ྊྦྷ࿵࿂ལྞྖ༿༹ཐ྘ཨ࿲ྡྸ༜ྦྷུལ༾༡༎ུ༺༚ྐ༛࿉࿁ྫ༤ིྏ࿝࿡࿈ོྣ༜༺࿾ཛྷྥ࿛ྥྶཾ༧ྲཌ࿀࿝༙ང࿖࿟࿒࿰ཹཕཁྫ࿻༑྅ྦྷྒྷསཔ༠༦࿛࿻ིགྷ༸ྟ༼࿐ྌྤ༮࿂࿟࿝ྣ༉࿝࿉ཊ༟ོྡྍྷཱྀཋ࿸ྔྡྷྖ࿑ྒྷཆཚ༥༪࿨༱཯ྐྵ༁༌࿄࿂࿗ྐ༩ྜཁ༩࿐འྎ࿞ྫ࿲༑༔࿦ྒྷྂ཰ཝ༕ཻ༖࿌࿏ཨྋ༂ྸ࿼࿼࿅ྍཚཱུྗ࿂ྒྷ࿃རྷྊམགཻྂྎ࿝࿡࿂྇ྞྖཾ༙ཛྷ࿏ཀྵ༄࿀ག࿯࿚༃࿟࿦ཤ྆࿂࿉ྦཤཝ༪ྍི࿠༰ོཁྀ཈༛༰༦༜ཇ༵ྯྕཊ࿷྄༵࿞ག༸༗ྚདྷ྅༺࿱༥࿔ཏྰི༤ཀ࿇࿹ྒྷ࿈གྷ༰༪࿦༃ྫགྷྂཊྨྸུྲ࿼࿂༢ྐ༎་ཻ࿒࿆ྊོྰི࿲༄࿇ྦྷྒྷ༸྿༰ྖ༺༂ྫཧྂདྷ࿷ྸ࿯ྨཽ࿂ཨྐ༚ཻུ࿒ཤ།ོ༔ིྒྷྜྷ࿇࿹࿵ཬ྿ིྖ༅࿾࿢གྷ྘༑࿷྇࿯ྨ༖༂༢ྚ།ུ࿟࿒࿆ྷོྰྫསྜྷ༩࿹࿍༸྿༰༡࿞࿾ྞགྷཬ༆༿࿆༧ྡཱ࿕༢ྲདྷཻུྦ༇ྷ༛ྰབྷ༤ྜྷ࿇ྦྷ༤༸࿄༰ཅ࿦࿾ྫ༦࿘༆ཁྸ༧ྲ࿦࿂࿶གདྷཀཻཫྸཅོྍ࿐༤࿑࿇ྜྒྷ༸྿ྞ࿙࿦ཱུྫ༦ྂཀྵང྇༃ྲ྄࿂ཿྐདྷུ࿟༦࿆࿔ོཌྷི࿿ྜྷ༓࿦ྒྷ༸྿྽༇࿦࿾ི࿋ྂ༆࿷ྸ࿯ྲཱ༈ྡྐདྷུ࿟྿༢༫ཫྐྵི༤ྜྷ࿇࿹ྒྷ༸༛྅ྖ༉࿾࿹གྷྂ༆ྡྡ࿯༄ཱ༿༢༃ྏཀཚ࿒࿾ྷ࿩ྰི༤࿑ྃ࿹࿱༸ྉ༰ྖ࿦ཱཱུགྷ྘༆ཤྸ࿯ྲ༮࿾༢཭དྷཀཻོ࿆࿔སྰི༤཭༙྆ྒྷ࿈ཥ༰ྖ࿦མྫགྷྂཊ༈ྸ࿯ྲ༖࿂༢ྐ༎༂ཻ࿒࿆༫ོྰི༤ྜྷ༻࿐ྒྷ࿣྿࿫ྖ༺࿆཈ར࿇༆ྀ࿐ྫ࿚࿺ཇཆྀྭཙ࿉࿱ྫྷྷ༕ྰཛྷྣ༰࿧ཁདྷ࿛༞ྚཫན࿽࿼ཡ༗ཊ࿷ང࿬ྜྷ࿚ྪ༾࿹༟ཱུུ༱༶ྦ࿙࿸࿬༝࿑༓࿡ཚ࿈྿࿀ༀྐ࿽ྣྏ྘༆བྷབྷཻྜྷྮ࿢࿶ྐༀ༈ཎ࿱འྒཫྰག཈ྸྊ࿉ཻ༹༛༰ྥྸ࿽࿌༦྘༄ཨ྇࿯ཱྀ༳༙ྡྔྲྀཀཻཞ࿼࿓ྎྕ༏࿲ྜྷ࿃࿶ཫ࿊࿹࿌༡࿦ྜ࿾ཪྶ༪ྶ཮ཐྲྤིཎ༺ྒེ࿉࿱མཝ༯ཱི࿠མ༛ཱྀ༪྽࿪ཌྷ࿧ཌ࿚ྸ࿇ྮ༦ཻྀ༵ྜྷ࿚༈࿤ཅ࿜ྑཻས࿉ཹྏྡླྀ༾ཎ࿭ཁ༡༷࿉ཌྷཞ࿦ད࿕࿇གྷ྿༮ྵྡ࿽ྜྷྑྡྚ༎ྌཨྦ࿆ཪྌ༥ྪཚྰ༓࿹༸࿨ཱི྆࿖࿄ཱུྫྔྊ࿴ཎཞ༼ྨཱ༮༿࿦ཥཀ༽࿒࿾ྷོྰ༰࿿࿑ྶ࿹࿱༸྿༰࿪༉ཱུཷགྷ྘༆࿷ྸུ༄༮ཨ༢࿑དྷ࿳ཻྦ࿆࿔྾ྰྫ༤ཝ࿇ྦྷྎ࿈࿃༰࿪࿦࿆ྫ༦ྲྀཊ༇ྸ࿯ྲ྄࿂࿶ྐ༎༥ཻ࿒࿆ྟོྰི࿲࿾࿇ྦྷྒྷ࿠྿ྞ༪༺༠ྫཧྂ༪࿷྇࿳ྨ࿹࿂༢ྐ༎ུ࿅࿒ཤྲྀོྰི༴ྜྷ࿇࿹࿵࿪྿ྞྖ༉࿾༰ཟ྘ྟ࿷ཤ࿯࿖ཱ༿ཌྚྋཻུ࿒྇ྷཫྰྫ༱ྜྷ࿇࿹࿵༸྿༰༡༼࿾ིགྷྲྀ༆ང࿆༧࿽ཱ༂༢࿑དྷ࿗ྀྦྨྷ࿡ྰྫ༤ད࿇ྦྷཛ༸྿༰༪࿦࿾ྫ༦ྷ༆ྡྸ࿯ྲ༖࿂࿶ཌདྷཀཻ྿࿆ྷོྍ࿥༤࿑࿇࿐ྒྷ༸྿ྞ༗࿦࿾ྫཟྂ༆࿷࿾ཾཤ࿦࿂ཝྐ༣ུ࿟࿡ཞྷ༯ྰཱིཅ཮࿔༥༷࿊࿴཈༒࿹࿾མ྽࿣ྉབྷྜྷ༁ྜྷ࿄ྪ࿶ྐྈ࿬྄࿱ཤ࿔࿐ཬྫ༤ྍ࿨ྫྗ༁ཟྞྖ་བྷ࿬དྷཨ༎ྡྸྀ࿑་ཱ།ྒྷ༎ུཝས༥༆྿࿲ྼ༴ྜྷྏ༜ྙ྿ཋཙ࿻ཱྀུ࿼ཽྐ༬࿷࿚ཱྀྐྵ༂༹ཷཻ྽࿇࿑࿛࿆࿻དྷཁ༠༟ྐྵཋྱྀ྾࿄༰༏ཆཝ༵༬ཋྷ࿶࿾྆࿵༮࿂༿༔ོ༜࿝༙ྭྟོིཝ࿣ཱྏ་ྷྎྔྐཥནཱུ࿼ཆ࿂༬࿷ེཿ࿥ཛྷ࿼཮གྗ࿇࿂࿛࿆࿡ྌྫྸྃབྷྊ࿝ལྎ༛༰཰མཇ࿌༦ཀྵ༄༂ག࿯ྪྱྰ࿦༉࿏ྞ࿉࿹༊ྛོ༥ྪ༒མཉ࿰ཞ࿊࿐࿪༡࿦࿉ཐ࿪ྒྷ༪ྏ࿋ཐྲ༥ཱྀ࿺ྦྷ࿏ཌྷཙ࿱ཤ༑༙ྚཆ༤ཱྀྡྷ࿺ཪྗཋ༥࿿࿗ྜཛྷ࿏ཨཥ༿ྸ༼྄ཌཨ༹࿫ྈ࿐࿦ྶ࿥༆྿࿲ཙ࿨ྜྷ࿧࿰༕࿍྘ཚྈ༜ྰ࿂ྶ࿩༴ཚ༺ལ࿜ཻྰྡ࿑ཿཛྷ࿫࿒༅࿮ྊག࿸༏ྲྊ࿉ྀ࿧ྥ༰ྒྷྪལཱུཉ࿱ྉན࿑༜࿟࿽࿤༠༔࿒࿐࿳࿱༥࿔྿࿲༥༴ྜྷྕ༠ཞ࿲༡࿖༑ན࿓༠࿮ྂྒྷུྚཇ࿀ྸུྡཅྉཌཻ࿭࿼༷དྷ༁༁༝ྲ࿊࿒ཱུྻ྿࿂࿲ུྞ࿎ྡྷྶྷཿ࿓༈ཱཱུ࿝ཱཻུྉ༈ཱུཅ࿑࿘༙࿩ཆ༤ྯཧ࿯࿄ཥ࿊࿎ྦྨ༖࿌࿏ཀྵྲ་ག࿯༼༊྄཯ྍ࿮ྞ࿉ྦ࿾༶࿾࿬ི࿣ྍབམཊཧ༞༄༌࿪ྨྫ༾ྭྛ࿀࿢་༠࿶༈࿶ྔ༛ྑཻ༭ྐཞའ༿࿾ྩྸ࿁࿎࿨࿊࿉ཱུཞ࿦༰༢པ࿛༤༵༜྅༠࿗༲ྡ༗ླྑཻྷྜ༱཰ུཚ࿠༔࿡་࿨࿊࿹྇༨࿦ལ༹ཊ࿮ཫ༜ྚ༁༌༯ྖ࿗ྐ࿮཮༿ྗྜ࿲༾ྜྷ࿢ྍ྿྘࿹ྖྼ࿭࿑ྎ࿟࿽࿌ཏྑས࿽ྸ࿞༺ཐ༹࿀࿫࿒ྴ࿳༚༶༝ཬཤ༂༑༶࿇༙ྒྷ༸྿༰ྖ࿦཈ིཏ࿶༼༂ྸ྄཮ཱུཌྷ༹࿝ྗ࿂ྎྭརྷྌ༜ཤ࿃༺྽࿝࿡༿࿧ྯྖུ࿑ཌྷྥ࿣ྦ࿶࿸࿗ྖལད༢྅ླྴ་༎༙ཟསྫ༳ཪྰྶ࿫ླ༴འ྇࿋ནྸ࿮࿓༓༆࿝࿢ཝ༔࿅ྜྡག༚྆ྲྀ࿛࿆ྙྟ༂ཌྷ༒࿺ྊ࿝࿵࿈࿉ཷ༡࿦྄࿕༗ཫ༌ཱུ྇࿯༠࿟࿚༮ྔྞཀཻཅ࿟࿴࿪ྕྏ࿲ྜྷ༞ྴ࿈ྥོྣ࿵࿹࿾ཙ༪࿿࿵༹ྜྷ༁ྜྷ༮ྪ།࿺༎ུྜྷ༡ྫཧ༙ཾྫ༤༮ཛྴྮ༿༆ྞྖྡ࿑࿎࿔ཀྵྲདག࿯བྷཌ༹༔ཚཟེ࿉࿡ཞ࿄ྭྰ༢ྣྨྠ࿫།࿵ྊ࿆࿨ལ༰ཛྷ༆ཉ࿧ཿའྶ࿾ཱཨ༂࿢ྒྷ࿼ཌ༞༠ྒ༡࿞࿬࿻ྷ࿝࿦ྒྷ༯཰࿳ཹ࿟࿹ཨ࿏྘༪ྶ࿲ཐྲ࿅ྑ༖࿹࿴ེ࿉࿱࿓འ༯ྰདཅ཮ྶ࿶྆࿊࿴ཹ࿥࿹࿾དྥཛ༝ྱ࿦༁ྜྷ༮མ༢཭དྷཻུ྿࿆࿔༦ྰི༤ྚ࿇࿹ྒྷ࿈࿱༰༆࿦࿾ྫགྷྂཊྲྸུྲཱ࿂༢ྐ༎༥ཻ࿒࿆༫ོྰི࿲༊࿇࿹ྒྷ࿠྿༰ྖ༺་ྫ༝ྂ༆࿷ཱུ࿳ྨ࿞࿂ཐྐྗཻུ࿒ཤ࿓ོ཮ི࿻ྜྷ༘༙࿵ཀྵ྿༲ྖ༖࿾ྐྵཟ྘ྙ࿷ྸ࿯࿖ཱྪ༢ྚ༪ཻུ࿒ཱྀྷོྰྫཥྜྷྌ࿹ྎ༸྿༰༡༰࿾༲གྷྗ༆༈࿆༧ངཱ༁༢དདྷ࿯ཻྦ༠ྷ྿ྰྜ༤ྜྷ࿇ྦྷླ༸༛༰༒࿦࿾ྫ༦ྟ༆ཁྸུྲཱ࿂࿶࿤དྷ࿳ཻ࿡࿆༑ོྍཱ༤ྚ࿇࿹ྒྷ༸྿ྞྏ࿦࿾ྫྠྂ༆࿷྇ཛྷྲ༉࿂ཌྐདྷུ࿟࿄࿆࿘ོྰི༤ྜྷ༓ྜྒྷྊ྿༉ྖ࿦࿾ི࿋ྂཊ࿷྇࿯ྲཱ༈དྐ༚ུལ࿒ཤྷཫལི༤ྜྷ༩࿹ྒྷ༸༛྅ྖ࿹࿾࿀གྷྂ༆ྡཿ࿯༳ཱ࿂༢ྐདྷཀབྷ࿒࿆ྷ༛ྰི༤࿑཰࿹࿭༸࿡༰༪࿦ཱུ࿦གྷ།༆࿷ྸ࿯ྲ༮ང༢࿑དྷཻོུ࿆࿔༦ྰི༤࿇཭࿹ྒྷ࿈ྒ༰༒࿦༳ྫགྷྂཊགྸ࿗ྲ༉࿂ཌ཭༎࿽ཻ࿡࿆༑ོི༵࿲ྨ࿇࿉ྒྷཉ྿༰ྖ༺༿ྫཏྂ༆࿷ྸ࿯ྨ࿢࿂༢ྐ࿔ཻུ࿒ཤ༒ོ཮ི࿏ྜྷ࿇࿹࿵ྌ྿ྞྖ྄࿾ྫགྷ྘ྊ࿷ཤ࿯࿖ཱ࿂༢ྚ༒ུ࿝࿒མྷ࿒ྰྫ࿵ྜྷ࿊࿹ྒྷ༸྿༰༡ྞ࿾ྫགྷ࿓༆࿷ྸ༧ཙཱྪ༢཭དྷཻུྦ༌ྷ྿ྰ࿞༤ྜྷ࿇ྦྷ࿋༸ོ༰༪࿦࿾ྫ༦྆༆ཿྸ࿯ྲཱ࿂࿶࿯དྷ࿳ཻཏ࿆ྷོྍ༹༤࿑࿇ྦྷྒྷ༸྿ྞ༚࿦ྸྫ༝ྂཊ࿷྇࿽ྲཱ࿂ྑྐདྷུ࿟࿩࿆ྛོྜི༤ྜྷ༓༲ྒྷ༎྿ྫྖ࿦࿾ི༯ྂ༆࿷ཱུ࿯ྲཱ༈དྐ༟ུལ࿒ྸྷཫ࿰ི࿋ྜྷ࿇࿹ྒྷ༸༛ྐྵྖ༖࿾ྫགྷྗ༆ྡ༿࿯ྲཱ༪ྟྐདྷཀ྅࿒མྷླྰི༤࿑པ࿹࿱༸ོ༰༪༉྄ཱུགྷཀྵ༆ཙྸ࿳ྲ༮ཀ༢࿑དྷ࿯ཻ࿒࿆࿔ྉྰྫ༤ཱི࿇࿹ྒྷ࿈཈༰࿪࿦࿆ྫགྷྂཊ༄ྸ࿗ྲ༉࿂࿤ྐ༎ཛྷཻ࿡࿆ྷོྰི࿲ཾ࿇࿹ྒྷྷ྿༰ྖ༺ཛྷྫཏྂ༨࿷ྸ࿯ྨི࿂ཐྐདྷྀུ࿒ཤྲྀོྰིྥྜྷ࿇࿹࿵འ྿༲ྖ༉࿾ྫགྷ྘ཪ࿷࿾࿯ཤཱ࿂༢ྚ༬ུ࿝࿒༊ྷོྰྫྒྷྜྷ༓࿹༛༸྿༰༡࿢࿾࿼གྷྗ༆ངྸ༧࿑ཱྪ༢࿽དྷཻུྦ༥ྷ྿ྰཽ࿿࿶྆ྦྷྈ༸ོ༰ྟ࿦࿾ྫ༦ྊ༆ཿྸ࿗ྲ࿢༿࿶ཾདྷཀཻྎ࿆ྷོྍཎ༤ད࿇࿐ྒྷ༸྿ྞྔ࿦࿾ྫཹྂ༆࿷྇࿕ྲཱ࿂࿳ྐདྷུ࿟༦࿆࿘ོ཮ི࿿ྜྷ༓࿺ྒྷ༸྿ྫྖ࿦࿾ྫཟྗ༆࿷ག࿯ྨཱ༈࿤ྔ࿐ྑཻ࿣࿌ཛ༾࿑ཌྷ࿮྄ྈ࿳ཫ࿊༙ྫྷཞ࿦༜མ༎༝ྒཀ༲ྜ࿬༧ིྡ࿑ངྤ࿜࿒༹ཟ༘࿆༧༑྇࿒ངྷཀྵ࿇༲࿖ཛྷྲྫ༘༞སཻ༃ན༺༢༮཮གྗ࿳ྒྷཽ࿎ྷ༸ྜྷ࿸༬࿀ྦདྙ࿩༐༢ཛ༃࿀ྚ༫ོྉཆྫ༮࿉་ུཐྔ࿔ཌཻ༫༙࿃བ༄ཾཹ༺࿊࿡ཿཅ྿ཌྷཔ༇࿀ྱཅྉ༐࿀࿥༽࿀ྑྞ༹ྍ྆ྵ࿳࿱མྚ࿊ཱི༸࿺ྒྷྜྷ༕༘ྔཀཋཌ཯࿶༎࿨ྃ༰࿞࿬ྜྷ࿚ྪ།࿸࿠ུྨཹྐྵ࿮ཋྐར༘ྞྎཾ࿡࿈࿱༰ྖ࿦࿾ྫགྷྂཊགྸ࿯ྲཱ࿂࿶཭༎࿽ཻ࿒࿆༑ོི༵࿲༊࿇࿹ྒྷ࿠྿༰ྖ࿦མ༲གྷྂཪ࿷྇࿯༌༯༕ྱྐ࿋ྡ྅࿔࿀༨༫࿂ྜྷ࿪ཎྊ࿉ཻཪ࿄༰ྭ༶༉࿾༷྆ྼ࿶࿾࿊྘࿐࿂࿕࿚ྼལ༊ྛེཋཫཌྷ࿩ཀྵྤ࿇ཁ࿠࿵དྷཤཛ༇༲ྣདྷ༓༆ྰྜྷྰཱི༈ཨ༂ག༚྆ྯ༷࿆྿དྷ༂༵࿣༉གྷཾྲྀྺ࿴࿥༡༺࿓࿌࿮༷ྂཡྐྵ࿬࿫མུྡ࿔ཀྵཌཻྠ༃༷༘༂༁༝ྲ࿯ྀ࿭༸༾ཱུ࿱཭ཙ༈࿏ྶ࿖࿶྇࿯࿚ྸྱྡ࿑࿷࿹࿫࿒༰ྕྌ࿳཮ྷྸྊ࿉ཻ༞༣༰࿴྇཮༵ྏ࿩࿱ནདེྜྷ࿚ྪ྘྾࿠ུ࿤ྌྰ࿍ྶྞ༂ཀྵྀྼྜྷ࿍࿈࿱༰ྖ࿦࿾ྫགྷྂཊགྸ࿯ྲཱ࿂࿤཭༎࿽ཻ࿒࿆༑ོི༵࿲༊࿇࿹ྒྷ࿠྿༰ྖ࿦࿆༲གྷྂཪ࿷ག࿯༌༯࿂࿗ྐཛ࿉༂༑ྰ࿧ྎ࿞ྫ࿲༑༹༺ྒྷྡྷྼཝཹྱབྷྚ࿘༝཰࿶࿸࿇ྦཎ࿂ཽ࿚༻࿢࿂༓࿺ྫྷ༎࿼࿬༝༫ྛ༺ྒྷ࿨ྷ༶࿙ཝྴ༁༒࿣཰࿶࿸࿊ྡ࿐࿂ྀ༙࿍༮ཾ༡༰྿྿࿋ྼ༴ྜྷཹ࿸ྊ༦ྔ࿀࿋ནྸཹདྷ༓༆࿰ྐྀ࿌ཻིྡག༎࿳ྒྷ࿿རྷ༐རཀ༨྇྽࿝࿡༁࿏ྯྖ༢ིཾ࿧࿲ྣ࿶࿸࿇࿵࿐࿂ཽ࿾࿧ྐངཊ༥༆ཫ཮࿩ཟྤ࿇ཾ࿛ྒྷ༆ཤཫན࿽࿮ད༓༆༧࿀ནཇ༁ྜྡག࿷࿂࿟࿒ྚྮྟ࿞ྫ࿏༫࿡࿦ྒྷ࿨࿣࿖ས࿗ྚ࿌࿏ཾ࿸༂ྸྫ༅ཻ࿅ཎཱུྗ࿂࿝࿹༊࿠ོ༈དྻཎ࿣ྚ༒བ࿇ྪ࿮ཻ྇࿾༓༟༪དྷཝཐྲཐཀ྅࿺࿁࿝࿷༎ཤཊོྰི༤ྜྷ࿇࿹࿵ྫྷ྿༰ྖ࿦࿾ྫགྷ྘༚࿷ྸ࿯࿖ཱ࿂༢ྚ།ཻུ࿒࿆ྷོྰྫགྷྜྷ࿇࿹ྒྷ࿠࿒ྫ༡ི࿾ྫགྷྂ༆࿷ྸ༧མཱ࿂༢཭དྷཻུྦ༃ྷོྰྞ༤ྜྷ࿇࿉ྉྏ྿༰ཉ࿦ཱྫ༦྘༌ཙ྇࿯ཱྀ༥࿝ཚཅ࿐ཀཻༀལ༨༚ཛྜ࿲ྜྷྼ࿰࿣ྉ࿐༲༡࿦࿅࿕ཛྶ༪ྏྮཐྲྡ྄ཱྀ࿼࿏཯࿦ྒམ༶༔ྍི཈བྷྊ࿝࿱༿༡࿟ྖ྇ྤ࿯༎ྛྎཱྀ࿼࿼࿅ྡབྷངཌྷཹུ༹࿪ྜོ྿ཛ༼༴ྜྷ༦ཱིྲྀ࿍ྔཛྷྦནཱུ࿼ཆ࿉ཊ࿷༼ཿྀ࿯༸ཁྚདྷབྷཐྃ࿚༶ཨྍི༟཯࿡ཛྷ࿱༁࿜ྯྖཻྜྷ࿗ཪ࿧ྣ࿶࿸࿗༒ྶཁ༢࿫࿮࿐ཙ࿣༲༝ྏྍྫཚཹ༓࿹ྌༀ༩ཿ༌࿟ཱུྫ࿔࿮ྎ࿌ྫྷ࿷ྨཱ࿥༉࿉ྠ࿇༮ྦ࿆ཟ༡࿞࿬࿲༶࿗྿࿭༸ཋ༳ཟ࿕࿼༌࿏ྶ࿖࿉ག࿯༲࿰࿶༇࿹྆࿂࿉࿡࿓༐ོྰ࿢࿀ྑ྘࿹༣༻཈༿༛ཁ࿽࿌ཏ࿶࿱༂ྸ࿜༥࿑ཨཷཱུྗ࿂࿟࿡འ༊ཫྰ༧༩ཇ྿࿒༎࿈྿༌࿒༳྄ྣ࿘྘༆࿟࿑࿕ཎ༉༸཈࿸དྷྜ༉࿔ྴ࿒ྼ࿞࿬࿻༑༖༺ྒྷ࿍཰ྜྷྔགེ྇༒ྒཔ཮ལ࿗༒ཨཁ༢ཚཫལྸཊཱྀ࿋ྎྍྫྍ࿏༓࿹༷ྼྔ࿥࿖྄ཱུྫ༴྾࿮࿶ཞ༐ྨཱ࿉ྦྷཽྗ྆ཬྦ࿆࿓࿇༄࿬࿻༫༫ྵྒྷ༾ༀདྉ࿯཭ྰ࿋྾ཅཷྫཝ྅࿚ུཐ࿔ཫཌཻ།༅༴༗࿕࿀࿪ྲ࿊࿒༭ྻ྿ཌཛཾཌྷ࿯ཪྶྷཿའ࿾࿗ཱྍཌྷ༳༦࿉༢ཊྞ྾༑༊࿂ཞྸྊ࿝࿵ྊ࿐࿱༨࿦࿚ྰ྘༕ྛཡ࿸༁༒࿏ཁ༢ཱུ༐ཎཝྲྀ༖༆ྎ࿋ྒ࿲ྜྷ༦࿸ཅ࿊༛༲ྲབཱུྫྡྷྊྡྷནཞ྄ྨཱ༮༈࿬ཥ྆ཿྦ࿆࿧ྊྯ༵࿲࿑࿳࿙࿭༸༫ཙ࿱༠࿑༈࿏ྶ࿖ཛྷག࿯ཇ࿺࿌ྐྵཌྷ༷࿂࿉࿉ྑྛོ༥ྱྋ༮ྮ࿜࿡࿊༙ཀྵ༡࿦ྚ༥࿈ྶཊཙཞླྀ࿾ཱྴྫཆ࿍ཱྀ༄༡࿀࿡འྫ࿬༔ཱུྂ࿹༆ྕྔྍ࿴མ༖ྚ࿇࿱࿮࿶྇࿗ྖ྿༈༢ཱུྭ࿉࿶࿉ཊ࿔ོ࿢ྨ࿣༳࿗ྮ࿵༸࿘࿕ༀནྸ࿮༝࿇༆ཇང࿞࿚༁࿝༙ཤ༩ཙ࿉࿱མྜྷཱུ࿌ི༚༳ཹ༠ཊ࿄ྌཝྒ࿯ཌྷྲཏྑ༱༂ྸཽ࿼ཀབྷ༉༅ཟན࿝࿹྄ྛོཙ࿑࿔࿀ཛྸ࿈ྈོཹ྘ྦྷ࿾ཾ༆ཋ༭ྀ࿥ྵཆཤཨྡག༚࿇༷࿆྇࿮࿇࿖ཤ༡༊ཋྱཕ࿪དྷ࿥༡ཱཞྕ࿮ྂ༏࿥࿀ཁ྄ླྀུྡ༗ུཌཻ༭࿉ོ༫ླྀག༝ྲ࿊࿡࿗ྏ྿ྤ༕࿤༰ྱ࿊༝གྷ࿆ྜྷ༁ྜྷ༉࿠࿛༃དྷ࿼ཱ༱࿫ྺབ࿷ཌ࿓཯྾࿝࿵ྊ࿹ཧ༡࿦ི࿸༴ོ࿖༅྇࿯࿉ྸྍ༇ཅྪཀཻྂ༶ཥྎྍྫྍན༓࿹ཕ༘ྲྀ࿥༄༄ཱུྫ࿧࿿࿮࿶ཞཚྨཱ࿝༵࿦ྗ྆ྈྦ࿆࿁ྂྯ࿬࿲ྚུྯ཈༸བྑ༤࿰ྚད྘ཕྛ࿥༺ཻ༙࿺ུྡྔྩ༄ཻ༎༰࿃ཊྸཚཊྞ࿒ཱིྮ࿲༆ཌྷ༑ནཞ࿈ྠྂ࿿ྍྰཻ༹࿾ྵཽཆ༦ྵ࿯ྶ༉༆ྎྍྜྍ࿉྘࿹༆࿧ྟ࿂༐྇࿺ཿཽ༦༬࿷࿜࿐ཽ༿༺༹࿟ྈཀ࿐࿒࿆ྷོྰི༤࿑࿙࿹ྒྷ༸྿༰ྖ࿦ཱུ༅གྷྂ༆་ྸ࿯ྲ༮༊༢ྐདྷ࿕ཻ࿒࿆࿔ཏྰྞ༤ཾ࿇࿹ྒྷ࿈ཧ༰ྖ࿦࿆ྫཟྂཊཱུྸ࿯ྲ༜࿂༢ྐ༎ཱིཻ྿࿆࿙ོྰི࿲ྑ࿇࿹ྒྷཕ྿ྫྖ༺ྤྫགྷྂ༒࿷ྸ࿯ྨི࿂༢ྐདྷཻུ࿒ཤྲྀོྰི࿍ྜྷ࿇࿹࿵ྌ྿༰ྖ࿦࿾ྫགྷ྘དྷ࿷ྸ࿯ྲཱ࿂༢ྚ༪ཻུ࿒༳ྷོྰྫསྜྷ࿇࿹༛༸྿༰༡༲࿾༰གྷ༓༆࿷ྸ༧༂ཱ༁༢༥དྷཻུྦ࿸ྷ྿ྰྞ༤ྜྷ࿇ྦྷྕ༸࿡༰༆࿦࿆ྫ༦༟༆ངྸ࿳ྲ࿦࿂࿶࿤དྷཻོུ࿆༫ོྍ༹༤ྜྷ࿇༙ྒྷ༸྿ྞྶ࿦࿾ྫགྷྂ༆࿷྇࿽ྲཱ࿂ཨྐདྷུ࿟࿴࿆ྷོྰི༤ྜྷ༓ཇྒྷ༸྿༰ྖ༉࿾ིཫྂ༆࿷࿾࿯ྲཱ༈࿽ྐདྷུཷ࿒࿆ྷཫ࿅ི࿿ྜྷ཰࿹ྒྷ༸༛༮ྖ࿦࿾༲གྷྲྀ༆ྡྐ࿯ྲཱ༿༢ྐདྷཀ྅࿒࿾ྷ࿒ྰི༤࿑ཅ࿹࿴༸࿡༰༡༉ཱུྰགྷྗ༆ཙྸ࿤༄༮ཌ༢࿑དྷ࿳ཻ࿒࿆࿔ཹྰྫ༤ྜྷ࿇࿹ྒྷ࿈཈༰ྖ࿦࿆ྫགྷྂཊྑྸ࿯ྲ༖࿂༢ྐ༎ྚཻ࿒࿆ྷོྰི࿲࿶࿇࿹ྒྷ༸྿ྫྖ༺༁ྫགྷྂ༡࿷ྸ࿯ྨ࿞࿂ྑྐྖཻུ࿒ཤ࿓ོཚིྕྜྷ༻༙࿵࿓྿ིྖ༉࿾༰གྷ྘ྊ࿷ཤ࿯ྨཱ࿂༢ྚ༒ུ࿅࿒ྸྷ࿡ྰྫ༱ྜྷ࿇࿹བྷ༊྿༰༡ྜ࿾ྫགྷྂ༆࿷ྸ༧ཿཱ࿂༢ཛྷདྷཻུྦ༠ྷླྰི༤ྜྷ࿇ྦྷ࿲༸ྦ༰ྖ࿦࿾ྫ༦༫༆࿷ྸྱྲཱ࿂࿶࿯དྷྱཻྉ࿆ྷོྍ༮༤཭࿇ྜྒྷ༸྿ྞྋ࿦྇ྫྣྂ༆࿷྇ྜྷྲ࿐࿂༢ྐདྷུ࿟༦࿆༗ོཌྷི࿏ྜྷ༓༮ྒྷཉ྿࿢ྖ྄࿾ིྦྂྩ࿷མ࿯༄ཱ༈࿑ྐདྷཻུ࿒࿆ྷཫལི༤ྜྷ༻࿹ྒྷ༸༛༹ྖ༅࿾ྫགྷྂ༆ྡ༁࿯༊ཱ࿂༢཭དྷཀཌྷ࿒࿆ྷ྿ྰི༤࿑ྔ࿹ྉ༸࿵༰ྖ࿦ཱཱུགྷ།༆࿯ྸ࿯ྲ༮࿾༢༶དྷ࿯ཻ྿࿆࿔ཹྰ༰༤ཝ࿇࿹ྒྷ࿈ཹ༰ྖ࿦࿾ྫགྷྂཊྸྸ࿯ྲ༖࿂༢ྐ༎ཛྷཻ྿࿆ྷོི༵࿲ཾ࿇࿹ྒྷྻ྿༰ྖ༺༿ྫགྷྂ༆࿷ྸ࿯ྨ࿢࿂༢ྐ༞ཻུ࿒ཤ༻ོ࿀ིྒྜྷ࿇࿹࿵༡྿࿢ྖ༮࿾ྜཟ྘ྏ࿷༳࿯༄ཱ༿༢ྚའུ࿺࿒྇ྷོྰྫྉྜྷ༻࿹ྎ༸࿒༰༡ྞ࿾ྫགྷྚ༂࿷ྸ༧࿷ཱ࿂༢ྐདྷཻུྦ࿂ྷོྰཽ༤ྜྷ࿇ྦྷོ༸ླ༰ྖ࿦࿾ྫ༦༑༆་ྸ࿯ྲཱ࿂࿶༢དྷཻུྮ࿆ྷོྍ࿐༤཭࿇࿅ྒྷ༸྿ྞ༞࿦྇ྫ཈ྂ༆࿷྇ྐྲ࿐࿂ུྐདྷུ࿟ༀ࿆པོི༵༛ཝ༓཯ྒྷྻ྿࿼ྖཱ࿾ི྿ྂཪ࿷ྡ࿯ྲཱ༈࿽ྐྋུ࿚࿒࿆ྷཫ༜ི࿧ྜྷ྆࿹ྒྷ༸༛༮ྖ࿐࿾༲གྷྗ༆ྡད࿯གཱ༇༢ཛྷདྷཀྰ࿒ཱུྷ࿒ྰྞ༤࿑ྋ࿹ྒ༸࿒༰ྖ࿦ཱུ༮གྷ།༆࿷ྸ࿯ྲ༮࿆༢ྐདྷཾཻ࿒࿆࿔࿁ྰི༤ྜྷ࿇࿹ྒྷ࿈࿁༰ྖ࿦ྲྫགྷྂཊྲྸ࿳ྲཱ࿂༢ྐ༎༥ཻ࿒ོ࿆ྃྰི࿲ྨ࿇ཎྒྷྊ྿༰ྖ༺ླྀྫཥྂ༡࿷࿤࿳ྨ༰࿂ཨྐ༞ུཇ྿ཤྌོ࿬ི࿏ྜྷ࿇࿹࿵༘྿༰ྖ༺࿾ྫགྷ྘࿔࿷ྸ࿯ྲཱ࿂༢ྚ།ཻུ࿒ྸྷོྰྫྠྜྷ࿇࿹࿱༸྿༰༡ྯ࿾ྫགྷྲྀ༆࿷ྸ༧ངཱ࿕༢࿑དྷ࿗ཻྦ༃ྷོྰྞ༤ྜྷ࿇࿹࿱ྻ྿༰ྌ࿦࿤ྫ༦ྗ༄ཿག࿯ྐྵྜྷ࿹࿚࿆ཏ࿂࿉࿉࿆ྛོུ࿾༗༵ྶག࿡࿊ོྣ྅࿹࿾ྰ࿈྾ཏ༙࿌ན༺༉ཕྐྵ࿸དྷ࿦࿳ྲྀྰ࿋ྌ࿯࿬࿻ྷྡྷ࿦ྒྷ࿋པ࿖཰༳༉࿌࿏ཀྵ࿖ྐག࿯ཱྀླྀ࿜࿂࿆྆ྵ࿯ྦཤ༶ྒྷ࿬ི࿃ྫ࿄ྨྌྺ࿴࿥༌༘ྨྫ཰ཉ࿔ཌ࿉࿬ྜྷ࿚ཕྡ࿸དྷ༰༖ཊབྷ࿋ཊ࿞࿬࿀ཧ༓࿹༭྾࿴࿥༒༯ྰཆགྷཛ཰ཻ࿞ཙ࿚࿽ུཐྔ࿦ྑཻྫྷ༔ྺ཰࿑༥༨༉ྋ࿜࿡࿊ོཹབྷ࿹࿾ྍ༩ཥྊྱ࿦༁ྜྷ༮ྪ྘ྍ༟ུྜྷ࿃ནཛ࿭࿼࿬༝༑ༀ࿦ྒྷ༕࿪࿗༦ྀ༉࿌࿏ཨྲྡྸྴ࿞ྸུ࿶ད࿷࿀࿜࿒ད༤ྏ࿕༧༬ཡྥཾ྆࿊࿴ྣ༈ྦྷ࿾࿶ཅ༤ༀ࿝ྚ࿉༺ྑྜྡག༚࿇ྰ࿛࿆ཪྏ࿷࿕༑༉྾࿝࿱࿂࿘ྯྖྚ༵ཛྷཬཛ཰ལི༧༌࿛ན࿶ྐ࿴ཷ༳༞ྫྷཏཫྰྸ༬࿀ྺ྿༞࿈྿ྰྠ࿎བྷི༦ཾ࿚༂ྸླྀཌྷ࿕཮ཱེུྗ࿂ྎ༃རྷྟ࿂࿎ཅཱུྏ࿝࿡༁༠ྯྖ࿰ྐམ࿈࿧ྦ࿶࿸࿊ྱ༮࿂༖ཱུྗ࿂࿝࿉༃࿠ོྸ࿽༬࿹ཹག྆།༐༧༛࿅࿼ཱི༗ྶ༪དྷ࿀༧ྲ༂཯ྫྀ༚྆࿟࿧࿆ྫྷཀྵཐ༈ྶ࿾࿧ྑ࿛࿛༏༢ཋམ࿽࿌༦ྃ༆࿷ྸ࿑ྲཱ࿂࿶༌དྷ࿗ཻ࿒࿆ྷོྍ༅༤ཝ࿇༙ྒྷ࿣࿒ྞ༚࿦མྫ༝ྂ༆࿷྇༥ྲཱ࿂༢ྐ༎ུ࿟ཥ࿆ྷོ࿥ི༤ྜྷ༓ྞྒྷ༟྿ྞྖཷམིཹྂ༆࿷ཤ࿯ྸ༖༈ྐྐདྷུྴ࿒࿆ྷཫ࿚ིྕྜྷ༗࿹ྒྷ༸༛ྦྷྖ༮࿾ིགྷ།༒ྡྪ࿯༊ཱ༁༢དདྷཀ༹࿒ཱུྷྺྰི༤࿑ཕ࿹༱༸࿒༰ྖ࿦྄ཱུགྷ།༆ཙྸུྲ༮་༢ྐདྷྱཻཫ࿆࿔༦ྰི༤༶࿇࿹ྒྷ࿈ྺ༰࿪࿦ཱུྫ༦ྲྀཊ༈ྸ࿎ྲ࿦࿂༢ྐ༎ྑཻ࿒࿆ྷོཌྷི࿲ཾ࿇࿹ྒྷ྇ྜ༰ྖ༺ཱིྫགྷྂ༒࿷ྸ࿯ྲ࿦༇༢ྐྊུ࿼࿒མྜྷང࿬ི཈ཱྀཟ༠ྮྂ࿴࿥༡༺࿓ཉ༦ྂ཰࿥ཻ༁༒འ༈༢྅༐༺࿉࿹༈࿔ོ࿢࿑ྺྲུཡ࿵༸ྃམཹནཱུ࿼ཽཏ༬࿷࿰ྵ༜ཱཻུ༵གྗ࿊༊࿛࿆ྺྏ࿸࿌ཀྵབྷྊ࿝ཻ྽༛༰ྼ࿤ཚཤཏཾཁ༂ྸྞཌྷ࿕࿌ཇ࿚࿱࿂࿟࿡࿓ཎ༯ྰ༔ྷཚༀང཰࿮࿴ཹ༾࿹࿾ྚྏཋ࿲࿉࿦࿬ྜྷ࿄ཱི࿶ྐཋ࿉࿆༎མྜྷཨ࿌ི།྄྿࿾༑ཀྵྻ࿬ྒྷ་ྜྷ࿌༦ཀྵ༌࿜ག࿯ྤཇ༮༇༲༷࿂࿉࿹཮ྛོ༜ར࿈མ༦࿜࿡࿊༙༶༡࿦༵ངྡྷྶ༪ྏགཐྲྑ࿶ཌྷཷ࿏ྡ༊࿱མཝ࿗ཱིྷྞ༯࿤༒ཹྌཿྥཀྀ࿯ཬཟཏ࿳༽ཷཇ࿚ྪ།ྍ࿠ཱུུསྐྵཧྩཆགྗབྷྏ࿝࿡ྊ࿐༛༓࿦ྵྚྛས࿋࿥ྜཷ࿑༂བྷཷ࿖ྦ༰ཾཅན࿧ྎ཮࿃ཐ༂࿇࿖ྗ༪࿔ཛྷ࿙࿅ཝྤཔཛབ࿞྄ན༙༢ིྡག༚྆༄࿛࿆ྫྷྔཆཀྙ࿼࿁༧࿱༿࿺ྯྖ་ྵྸཅ༴ཥཎ࿝༧༂ཱ࿂༢ུདྷཻུྦ࿸ྷ࿡ྰི༤ྜྷ࿇ྦྷ࿿༸࿒༰༪࿦ྨ༰༦࿘༆ངྸུྲཱ࿂࿶࿤དྷཻུ࿒࿆࿔ོྍ༉༤ྜྷ࿇༉ྒྷ༸྿ྞ࿔࿦༳ྫ༦ྂ༆ང྇༢ྲཱ࿂ྑྐ༎࿗࿟ཥ࿆ྷོ࿀ི༤ྜྷ༓ྜྒྷ༟྿࿉ྖ࿦࿾ི࿲ྂ༡࿷྇࿯མ༖༈དྐྻུལ࿒࿾ྷཫ༽ི༤ྜྷ༩࿹࿴࿠༛༺ྖ࿦࿾༰གྷྂ༆ྡ࿖࿯ྨཱ༿༢ྐདྷཀ࿜࿒࿆ྷོྰྜ༤࿑༭࿹ྒྷ༸࿞ཫྖ࿦ཱུ༹གྷྂ༆ངྸ࿯ྲ༖༂༳དདྷ࿅ཻ༶࿆࿔྿ཛི༴ྜྷ༐࿳࿈༷ྻ༂༑ནྫྷ༲࿮ྂཔ༅ཻེ༺ྸུྡཅདྷཀཻ཰༙ཫཅ཮࿩࿱࿷࿇༥ཕྈྃ࿯࿠༶ིྸྃ࿲༐࿗ྫ࿫ད࿽࿝࿷ལ࿋࿹࿆༏བྷའྎ࿞࿢ཚཷ྘࿹࿣཈࿙࿀࿠ཱི࿝࿌༦྘ྲྩ྇࿯࿐དྱྡྔཏཀཻཞ༵༣ྎ࿲࿂࿲ྜྷ༐࿳཰࿊༙ྮ༡࿦ྚ࿾ཊྶ༪ྏ༧ཐྲལཻ࿅ཡ࿒ེ࿉࿱མྜྷཨ࿬ི཈྄཈ྫྮྺ࿴࿥༡༺ཞཛ༦ྂ࿋࿥༅༜༒࿤༈༢མཋ཯ཤ࿉༫࿔ོ࿢ཌ༨ྵ࿳࿳࿵༸࿊ཌྷ༑ནྸ཈࿾༓༆༮࿝༜ྪ༃࿞࿕ག༚྄༷࿆྆༯ྼ༲࿽࿔࿰ྺ࿳༯྿࿴࿥༡ཱ࿓࿾ྠྂྕཱྀནྴ཯ྪཚ࿀࿾ས༜࿳དྷྐྵ༆ྎཛ༳ྈྜྷ༯ྨཅ࿿྘ྸྭཱི࿆࿂ྈྭྖ࿷ྸ࿯ྲཱ࿂༢ྐྥ࿳࿴ཧརྷ࿇࿼ཱི༎࿼࿒࿺༕࿈༛࿮࿱༺࿾ཌ࿋ཋༀདྷཱྀ༧ྲཻ࿫༙཯ཿ༲࿟࿒༹འྼ༊࿃ྦྷ࿑࿇ཝ࿈࿮࿴ྞ༡࿛༽ཆགྷ࿡ླྵ༵཯ཽ࿕ག།ཇ༟ུྚ࿭ྐ༯ྗ࿑ཝ྘࿘࿄࿦ྒྷ࿿࿣࿶༷࿳࿟ཱི࿪ཨད༂ྸཇ࿽࿆ྰལཱུྗ࿂࿝࿉ྒྟོ༊ཌ༨༖࿨࿫༾༤ྖཌྷ༑ནྸ࿮ཝ࿇༆࿯࿐࿉࿉ུྑ༹ྜ࿡ེ࿉࿱ཤ࿔࿐༳ྫ༤཮ྥཨ࿡༿༘ྞྖཻྰྑ࿏ཨ྽ྡྸ࿚࿌གུ།࿼༎ུ༮༏ཝ༆྿࿲ཞ༴ྜྷྏཁཬ༯ཋ༳ྒྷམྸ཈࿕ཞ༆ྱ࿌ནྪ࿸༮ཻྯ࿋ཷ࿶༗ལ࿧ྎ࿞࿢ྍ࿀྘࿹འ࿛༸ྰས༢ལཙ༦ྗ༌༰ཾ࿯ཌྷ࿗ཚ༮࿞࿮ང࿦ༀཝ࿓༾ཙྰྫྷྐྵ࿗ཹ཈༸྆༔ྠ࿶࿚ཐ༪༷༝༲༺༙ྴ༁༖༁དདྷ࿳ཻ࿒࿆ྷོྰི࿲࿑࿗࿸࿵༸༭༇༗ྚའཾ༦ྂཔ྅ལཇ༒࿏༈༢࿉࿡ྚ࿾࿹ཻ࿔ོྜམྛ༮࿊࿒࿉ྻ྿ཌྷ༏༈࿬࿽ྡྷྶྷཿྫྷཧཱཱུྑེམྣྞ༥ༀ༥࿘࿹ི࿞༤བྷ྽ཾ࿨࿒࿪࿥༑༖ཞ༊྾ྂ༦࿯༠ྡཎླྀཇྦྷལྎ྄࿉ྦམྜྷ࿡ྍིཹ࿺ྒྷ༊ྀྊ༛༰࿿ྸ࿹ྱཡྀཊ࿷࿚ྦྷ༔༧ྪ༾ུ༟ུད࿃ྵྒྷ༚༂ཌཬྚ࿯཭ས༸ྷ࿾ྔ༿࿉ང༫༴ྭ༺ྐཙ༌ྮ༰ཱུྐ࿲ཁ࿯༓ྫའྗྐ࿶ཕཌྷྮ࿶༎࿧࿘ྞ༒࿛ྠིགྷ༴ྡྷ࿐࿉྆ཌ༮࿂༉༌ྎ࿚࿴࿿ཤྷ།ྸུ࿣ྚ࿗ྤ࿭༸༐ཝ࿠༶࿚཮࿏ྶཊྡ࿓࿐࿾ཱ༺ཌྷ࿬གྷ࿦༉࿭࿼࿋ཊ࿞࿬ཚྫྷྂ࿹༡࿲།༶གྷལ཭࿾࿋࿿ྷ࿶ྫྷ༙࿾ཱ༜༰࿾࿿࿦ྜྷྌ༠࿇ྊ࿞࿬࿀ྫ྘࿹࿣ྭ࿘ཱུ཰࿟࿽࿌༦ཀྵྲ༁྇࿯࿫ྀ༹ྯ࿔༸ཀཻྶ༠ྙ࿪ཛྯ࿲ྜྷཟྜྷ࿛྽༛ྞ࿖࿅ཱུྫ྆྾ས࿝འཿྨཱྍ༿༹ྕྌ྄ྦ࿆ྕ༐ྫ༶ྍ࿆༓࿹ཀྵྂ࿴࿥༒࿛ྖྀགྷྒྡྷ࿺༽༲ཌྷ༠࿬ྯ࿦ྡྷ༹཭ྖ༶༆྿࿲ཙྈྜྷཟ࿯ཫོདྷཌྦྀ༼༈࿏ྶ༪ྏ࿕ཐྲ༳ཱ༈ཤ࿵ཙ࿉࿱མ༶࿘࿬ིྛཆ࿄ྜྷ࿙࿵༸࿥༒࿛༉࿅གྷཥ࿁࿫ྞ࿉ཆ࿯࿺྅༹༛࿦࿷ཞ༮འ།࿼࿬༝࿑࿊࿒ཤྻ྿༳࿲༈࿬ཱུ༴༟ཋདྷ༢ཐྲ࿯ྫྯན࿁༲༅༾ཞ࿦༯ྰྨ༩࿰ཏན༷࿊࿴ྞ༡༯࿽ཆགྷཹྛ༧༖༉྅࿚ུ༾ྨ༟ུ༳དྷ཭༛ྩཐ࿬༝༑ཕ࿦ྒྷྕ༐༹࿙࿰༉࿌࿏࿶༑ྡྸྀ࿼࿚ུ࿶དཙྦྷ࿜࿒༽࿡༾ཙ༿ྺ༅ྶྱ༷࿊࿴ྣ྽࿹࿾࿶ྭཟྟ࿝཮་༅༮༈྘࿧༎ུ༊ྗྀ༆࿐ྛྫ༤༙ྦྑ࿡࿂࿄ྞྖཱུ࿹࿽࿏ཨ༨ྡྸ࿞༇ླྀུཐྔ࿓ྑཻ࿘཮࿍ྖྸ࿶ྺིགྷ་༗࿊༛ྞ༌༇ཱུྫྩཉ༛ྰྫྷཱྀྨཱ࿶ཎ࿖࿋࿊ྑྦ࿆࿏ༀ༂࿽࿀༑༓࿹࿓ྺ࿴࿥༒༯࿹ིགྷཉྭྍ༔࿗ྖིང༢࿬྆ྵྜྷ༞࿢༛ཬྞག༝ྲ࿊࿒འྏ྿ྍྔྐ࿑࿖࿍༸ྉ༅࿞༁ྜྷ༉༸༚༃དྷ࿢࿾྆࿐྿ྟ࿷࿥༞ྯཉ࿝࿴༸༣༰ྖ࿦࿾ྫགྷྂ༪ྏྥཐྲ࿺༢࿺཯ྒྷཙ࿉࿱མྜྷ༖ཱི༞཯࿧࿾ྖ༯ྖ࿕ༀ࿆ྴྲ཰ྕ࿴༲༽࿞ྐྵྸ༈࿶ྔ༎ཀཻ༫࿟࿇༎ྕ࿓࿲ྜྷྏྴྲྀྼ࿹ྞ༡࿦ྜྷ༃࿙ཏ༄ླ྇࿯࿰༧ཇྡདདྷཌཻ࿒࿆ྷོྰི࿲ྚ࿗ྡ࿭༸འཝ࿠ྤྜྷ༹༗ྶ࿖྅ག࿯ྀླྀ࿜ཆ࿆༻ཱྀ࿉࿹ྞྛོྑ࿶࿣ཎྋ࿜࿡࿊༛༲࿖࿩ྨྫ།ྣོ࿥ྜྷབྷ༃ྜྷ༸ཅ࿸དྷཎཿ༾༲࿏དྷད༶࿀ྀ྘࿹༚ྂྟ༿ྛ࿟࿽࿌༝ྂ༒࿷ྸ࿯ྲཱ࿂༢࿑ངཡ࿫࿒཭ྫྷ཰࿷࿳ཞ࿾ྊ࿉ྀ࿳࿄༰ྉྐ྄ཱུཀྵ࿱࿙࿬྇࿗ྖ༞ཁ༢ཎྌ༰࿳ཞྐྵ༆ྎ࿲༡༴ྜྷཹམ࿠༯༩࿖༑ནྫྷྖ࿮ྂྛ࿝ངབྷ༺࿺ུྡ࿑ཿྡ࿫࿒ད༤༐༶࿗࿁ྐྵྊྦྷ࿱༿࿠ྯྖཨ༙࿑ྛྼྋ༧࿫࿊࿓࿐࿂࿦ཆ࿒ཱ༊ྗ༙ྼ༙࿽࿞༤࿹ༀྫཬྡྷཋ࿥༑༺࿆཈ར༓༆࿯࿐ྵ༺ྀཨྡག࿷ཋ࿫࿒࿚༕༆࿑༇ཀྵྲྊ࿉࿝ྙ༣༰཰ྸྐ༹ྈ࿁བཚ࿌ེྜྷ࿚༈࿤༗཭ྑཻས࿉ོ༫ི཮༾࿌཈࿂࿡࿊࿹བ༨࿦ི࿀།࿋ྛཎ཯ཡ༌༯༬࿗ྐ༐ཌྷཱཅི࿱ྠྯྫ࿏༫ྜ࿦ྒྷོ཰ྍ࿨࿽ད࿆࿏ཾ࿅༂ྸ༰༅࿸ནཇ༔྆࿂࿟ོཞ༪༕ྰ཮༬༳༛࿫ཫ།྆༂ྦན࿽࿮ད࿇༆࿗࿑༼࿐ུཇཚ༺ླཙ࿉࿱ཤ࿘࿹࿾࿞༤ཻྎ༿྆࿴༸ཙ༑࿄࿘ཆགྷ࿛࿋࿰࿝༵ྐྵུ྇ཬྜ༟ུ࿆༚ྚླ༪ཁ࿂༝࿑ྌ྿࿎ྏ྿࿑ྕྀ࿫ྪཉ༤ྼཌྷ༉࿷ྜྷྮླྀྱྐྌ࿉ྑ࿇༰ྣ྘ུ྇ྲྀྲྊ࿐ྒྷའ྿༰ྖ࿦࿾ྫགྷྗ༒༂ྸ࿯ྲཱ࿂༢ྐ༚࿊ྥ༷࿆ྼཋཙཌ༚༵བཱིཊྂ࿴࿥༡ཱྫྷ༅࿮ྂ࿴༼࿀࿫༼༢ྱྡཅ཯ཌཻༀདཋ༚ྡ་࿪ྲ༓ྦྷ࿝࿸༛༰࿻༊࿑཭ཆ࿁ཊ࿷ྐྵ࿕བྷྸཕཽྚདྷྰ࿸༓ཻཝ༫ྍི༡࿟ྊ࿝࿵ྊ࿹ྤ༨࿦࿉ཱུ཰࿄࿴༅࿸༁༒ཋཁ༢ཱུ༐ཎཝྲྀ༖༆ྎ࿋࿸࿲ྜྷོི༗࿊ོ࿮༻࿹࿾ཀ࿨ཫ࿵ྱཱ༁ྜྷ༮༁ཬ༄ྟུྜྷབ༵ྒ༾ཌ࿹༏ྫཹར࿨༕༓ཀ༑༯ཱིྀགྷ࿡ྕཱྀ࿜ཝྴལ༮ང཯ྎ࿢ཝྔལ༆ཫ཮ྺ࿼ྤ࿇࿜༯བ༗ཚཹན࿽ཹྟ༓༆༺ལྡཌྷ࿗ྜྡགངཎ࿟࿒࿌༦཰࿞ྫ࿻༫༘ྦྷྒྷྠྠ࿳ྠ࿛྾ིགྷཥ༷༙ཁྌར༮࿂ཽ࿾ྌ࿂࿝࿉ཿ༎ོྫྐ༑ཡ࿨ཱི༟།࿙࿤࿁ུ༹ང༎༛࿋༙࿥ྞ༵ླྀུྡ࿑࿷ན࿜࿒࿺༬ཅང༈࿩ྐྵྎམ࿛༦༑༲༌རྨྫ྆྾ཛ࿞ྀཡྰ࿶༁༢༁དྷཻུ࿒࿆ྷོྍྜྍྊ྘࿹༡ཀྵ࿇༳ྎ༊࿥࿌ཆ཈༬࿷࿹༜ྪ࿾ྑ཮གྗ࿳࿱ྗཤྷྛླྀ࿽༫ྚ࿯࿙࿭༸ྖ༶༏༃ྜ༁ཛྶཊཙའླ࿾ཱ࿉༽༺༷࿼࿸࿘ྀླྩཌ࿬ཚ࿩ྂ࿹ྌཀྵ༾༥࿨ྱ༜࿹࿋ོཫ࿶མ࿯ྲཱ࿂༢ྐདྷཻུ࿡ཞ༑༕ྰྸ༬ྰ࿄༥།༪།࿆༭ན࿽࿼ཆ༏༬࿷༼༺ྤྜྷ࿦࿐༙ྗ࿳ྒྷཅ࿤ྷཔ࿯࿤༟ྦྷཉ཭ླ༪ྟཤ࿿༈༅࿆༫༱ྃཆ༜༧༌ྮཞ࿗ྐ྆༺࿂ྗ཭༤ྔྐ࿩༾ྤ࿇ཙ࿄࿿ྔཌ࿍ྸྐཹ྅༓༆࿯࿼ྵཎ༿࿦ཚ༔༎ཛྷཻ྿࿆ྷོྰི࿲ཾ࿇࿹ྒྷ࿠྿༰ྖ༺ཱིྫགྷྂ༒࿷ྸ࿯ྨ༜࿂࿤ྐདྷ྄ུ྿ཤ༻ོ཮ིྫྷྜྷ࿇࿹࿵࿓྿༲ྖ༉࿾༲གྷ྘ྋ࿷࿾࿯༌ཱྡཌྚཉཻུ࿒࿾ྷ྿ྰྫ༱ྜྷ࿇࿹ྏ༸྿༰༡༜࿾༲གྷྂ༆࿷ྸ༧༇ཱ༁༢དདྷ༿ྀྦྪྷ࿒ྰི༤ྜྷ࿇ྦྷཛ༸྿༰༰࿦࿾ྫ༦པ༆ཿྸུྲྯ༿࿶ཐདྷ࿳ཻ࿒࿆༫ོྍ༉༤ྜྷ࿇ྊྒྷ༸྿ྞྻ࿦ྸྫ༝ྂདྷང྇༃ྲ྄࿂྇ྐདྷུ࿟༦࿆࿘ོ཮ི࿏ྜྷ༓ཇྒྷྊ྿༰ྖ࿦࿾ིཫྂ༆࿷ྺ࿯ྲཱ༈࿽ྐ༎ུ༽࿒࿆ྷཫྴིྕྜྷ࿊࿹ྂ࿠༛༮ྖ༺࿾༲གྷྗ༆ྡྨ࿯ྲཱ༈༢ཝྏཀཌྷ࿒࿆ྷཿྰི༤࿑ྋ࿹࿵༸࿒༰ྖ࿦ཱུ༮གྷ྘༆࿷ྸ࿯ྲ༮࿆༢ྐདྷ࿎ཻ࿒࿆࿔࿃ྰྫ༤༧࿇࿹ྒྷ࿈གྷ༰࿪࿦࿌ྫགྷྂཊཱུྸཀྲཇ࿂༢ྐ༎ྚཻླ࿆࿘ོྰི࿲ྑ࿇ཎྒྷཕ྿࿼ྖ༺࿖ྫཧྂྩ࿷༳࿯ྨྞ࿂࿶ྐྶྀུ࿒ཤྌོྍི༤ྜྷ࿇࿹࿵ྌ྿༰ྖཱ࿾ྫགྷ྘༫࿷ྸ࿯༌ཱ࿂༢ྚཀྵཻུ࿒ཤྷོྰྫསྜྷ༩࿹ྼ༸྿༰༡࿞࿾ྞགྷཬ༆ཱ࿆༧࿽ཱ༂༢༶དྷྫྀྦ༥ྷ྿ྰྲ࿿ད࿇ྦྷ࿿༸ྦ༰༒࿦࿫༰༦ྔ༆ླྀྸ༮ྲཱ࿂࿶࿤དྷྱཻ࿡࿆༑ོྍཱ༤ད࿇࿹ྒྷ࿠྿ྞྏ࿦࿾ྫཟྂ༆࿷྇ཿྲ྄࿂ཐྐ༩࿗࿟ཟ࿆ྔོཌི༤ྜྷ༓ཽྒྷྋ྿༜ྖ࿦࿾ི྿ྂ༬࿷ྑ࿯ྲཱ༈༁ྐ༞ུ཮࿒࿆ྷཫ࿚ི࿍ྜྷ࿘࿹ྒྷ༸༛ཷྖ࿐࿾ཽགྷ࿘༒ྡྪ࿯ཤཱ༿༢཭དྷཀ࿀࿒ྨྷ྿ྰ༮࿿࿑ཕ࿹ས༸༛༰ྖ࿦ཱེུགྷ࿇༆༿ྸ࿖༄༮༊༢༠དྷ༳ཻ࿒࿆࿔ཋྰྯ༤ཛྷ࿇ཿྎ࿈གྷ༰࿓࿦༖ྫགྷྂཊྨྸ࿶ྲ࿖࿂༢ྐ༎ཱིཻ࿧࿆ྉོྰི࿲ྑ࿇༅ྒྷ࿈྿࿼ྖ༺ྚྫ྾ྂ࿓࿷࿖࿯ྨྞ࿂࿳ྐ༚ྀུ࿒ཤ༻ོེི࿡ྜྷ࿇࿹࿵༡྿ཡྖ࿐࿾མཟ྘༟࿷ྨ࿯࿽ཱ࿂༢ྚྌུན